# 컴포넌트 개요: 13 소스 조회 결과 병합기
# 역할: 소스별 조회 페이로드를 병합하고 데이터 조회 추적 정보를 작성합니다.
# 주요 입력: 메인 페이로드 (main_payload) · 필수, 더미 조회 결과 (dummy_retrieval), Oracle 조회 결과 (oracle_retrieval), H-API 조회 결과
#        (h_api_retrieval), 데이터레이크 조회 결과 (datalake_retrieval), Goodocs 조회 결과 (goodocs_retrieval)
# 주요 출력: 페이로드 출력 (payload_out)
# 처리 흐름: 각 조회 분기의 결과를 입력 순서대로 합치면서 warnings·errors·trace를 잃지 않고 하나의 페이로드로 만듭니다.
# 유지보수 포인트: inputs/outputs의 name은 Langflow JSON edge 계약이므로 변경 시 모든 Flow JSON을 재생성하고 source sync 검증을 실행해야 합니다.
# =============================================================================

from __future__ import annotations

from copy import deepcopy
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, Output
from lfx.schema.data import Data

# 주요 함수: 여러 조회 분기에서 돌아온 source result와 trace를 하나로 병합합니다.
# Langflow 클래스와 단위 테스트가 같은 업무 규칙을 쓰도록 일반 Python 값 중심으로 처리합니다.
def merge_source_retrieval_payloads(main_payload_value: Any, *retrieval_values: Any) -> dict[str, Any]:
    payload = _payload(main_payload_value)
    source_results = []
    skipped_sources = []
    errors = []
    warnings = []
    for value in retrieval_values:
        retrieval = _payload_view(value)
        if retrieval.get("skipped"):
            skipped_sources.append({"source_type": retrieval.get("source_type"), "skip_reason": retrieval.get("skip_reason")})
            continue
        source_results.extend([item for item in retrieval.get("source_results", []) if isinstance(item, dict)])
        errors.extend(retrieval.get("errors", []))
        warnings.extend(retrieval.get("warnings", []))
    next_payload = payload
    compact_results = [_compact_source_result(item) for item in source_results]
    existing_results = [
        _compact_source_result(item)
        for item in payload.get("source_results", [])
        if isinstance(item, dict)
    ] if isinstance(payload.get("source_results"), list) else []
    merged_results = _merge_items_by_alias(existing_results, compact_results)
    if merged_results:
        next_payload["source_results"] = merged_results
    if compact_results:
        staged_rows = (
            deepcopy(payload.get("_runtime_rows_by_alias"))
            if isinstance(payload.get("_runtime_rows_by_alias"), dict)
            else {}
        )
        for item in source_results:
            alias = _alias(item)
            if alias:
                staged_rows[alias] = item.get("rows", []) if isinstance(item.get("rows"), list) else []
        next_payload["_runtime_rows_by_alias"] = staged_rows
    trace = next_payload.setdefault("trace", {})
    trace.setdefault("errors", []).extend(errors)
    trace.setdefault("warnings", []).extend(warnings)
    inspection = trace.setdefault("inspection", {})
    retrieval_inspection = deepcopy(inspection.get("data_retrieval")) if isinstance(inspection.get("data_retrieval"), dict) else {}
    validation = retrieval_inspection.get("job_validation") if isinstance(retrieval_inspection.get("job_validation"), dict) else {}
    validation_failed = int(validation.get("error_count") or 0) > 0
    retrieval_inspection.update(
        {
            "stage": "13_source_retrieval_merger",
            "status": "error" if errors or validation_failed else "ok",
            "executed_source_count": len(compact_results),
            "sources": _trace_source_summaries(merged_results),
            "skipped_sources": skipped_sources,
            "preserved_existing_runtime_sources": bool(payload.get("runtime_sources")),
            "merged_source_aliases": [_alias(item) for item in merged_results if _alias(item)],
        }
    )
    inspection["data_retrieval"] = retrieval_inspection
    return next_payload


# 함수 설명: `_compact_source_result()`는 pandas용 전체 행을 source 결과 요약에서 제외해 동일 데이터의 중복 전달을 막습니다.
def _compact_source_result(item: dict[str, Any]) -> dict[str, Any]:
    return {key: deepcopy(value) for key, value in item.items() if key not in {"rows", "data"}}


# 함수 설명: `_merge_items_by_alias()`는 기존 alias 순서를 유지하고 같은 alias의 신규 조회 결과만 해당 위치에 교체합니다.
def _merge_items_by_alias(existing: list[dict[str, Any]], additions: list[dict[str, Any]]) -> list[dict[str, Any]]:
    result = [deepcopy(item) for item in existing]
    positions = {_alias(item): index for index, item in enumerate(result) if _alias(item)}
    for item in additions:
        alias = _alias(item)
        if alias and alias in positions:
            result[positions[alias]] = deepcopy(item)
        else:
            if alias:
                positions[alias] = len(result)
            result.append(deepcopy(item))
    return result


# 함수 설명: `_alias()`는 source_alias를 우선하고 없을 때 dataset_key를 사용해 결과 병합 identity를 만듭니다.
def _alias(value: dict[str, Any]) -> str:
    return str(value.get("source_alias") or value.get("dataset_key") or "").strip()


# 함수 설명: `_trace_source_summaries()`는 trace에 전체 preview/config를 복제하지 않고 상태 확인용 필드만 남깁니다.
def _trace_source_summaries(source_results: Any) -> list[dict[str, Any]]:
    summaries: list[dict[str, Any]] = []
    for item in source_results if isinstance(source_results, list) else []:
        if not isinstance(item, dict):
            continue
        execution = item.get("source_execution") if isinstance(item.get("source_execution"), dict) else {}
        summaries.append(
            {
                "source_alias": item.get("source_alias"),
                "dataset_key": item.get("dataset_key"),
                "source_type": item.get("source_type"),
                "status": item.get("status"),
                "row_count": item.get("row_count"),
                "used_dummy_data": execution.get("used_dummy_data") is True,
                "error_count": len(item.get("errors", [])) if isinstance(item.get("errors"), list) else 0,
            }
        )
    return summaries


# 함수 설명: `_payload()`는 Langflow Data/Message 또는 일반 dict 입력에서 안전한 dict 페이로드 복사본을 꺼냅니다.
def _payload(value: Any) -> dict[str, Any]:
    if isinstance(value, dict):
        return deepcopy(value)
    data = getattr(value, "data", None)
    return deepcopy(data) if isinstance(data, dict) else {}


# 함수 설명: `_payload_view()`는 조회 branch 결과를 수정하지 않는 읽기 전용 view로 꺼내 대용량 rows 재복사를 피합니다.
def _payload_view(value: Any) -> dict[str, Any]:
    if isinstance(value, dict):
        return value
    data = getattr(value, "data", None)
    return data if isinstance(data, dict) else {}


# Langflow 컴포넌트 클래스: inputs/outputs가 캔버스 포트와 JSON edge 계약을 정의합니다.
# 실제 업무 규칙은 위의 주요 함수에 두어 UI 실행과 단위 테스트가 같은 로직을 사용합니다.
