# 역할: Langflow 프롬프트 템플릿과 에이전트/LLM에 연결할 pandas 코드 생성 변수를 제공합니다. function case 선택 정보는 16번 Prompt Template에 연결하고, 실제 함수
#     코드는 별도 입력으로 넣습니다.
# 주요 입력: 페이로드 (payload) · 필수
# 주요 출력: 의도 계획 JSON (intent_plan_json), 소스 스키마 JSON (source_schema_json), 소스 미리보기 JSON (source_preview_json),
#        Function Case 선택 정보 JSON (function_case_selection_json), 출력 계약 JSON (output_contract_json)
# 처리 흐름: pandas 코드 LLM에 전달할 의도 계획, source schema/preview, 선택 helper와 출력 계약을 분리해 만듭니다.
# 유지보수 포인트: inputs/outputs의 name은 Langflow JSON edge 계약이므로 변경 시 모든 Flow JSON을 재생성하고 source sync 검증을 실행해야 합니다.
# =============================================================================

from __future__ import annotations

import json
from copy import deepcopy
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, Output
from lfx.schema.message import Message

PROMPT_INTERNAL_JOB_KEYS = {
    "source_config",
    "filter_mappings",
    "standard_column_aliases",
    "row_identity_columns",
    "default_detail_columns",
    "context_columns",
    "required_param_names",
    "trusted_catalog",
    "catalog_ref",
}
RETIRED_OUTPUT_CONTRACT_KEYS = {"row_identity_columns", "context_columns", "default_detail_columns"}

# 주요 함수: LLM 프롬프트에 연결할 변수만 선별하고 JSON-safe 문자열 또는 dict로 정리합니다.
# Langflow 클래스와 단위 테스트가 같은 업무 규칙을 쓰도록 일반 Python 값 중심으로 처리합니다.
def build_variables(payload_value: Any) -> dict[str, Any]:
    payload = _payload(payload_value)
    schemas = _source_schemas(payload)
    previews = {alias: rows[:5] for alias, rows in payload.get("runtime_sources", {}).items() if isinstance(rows, list)}
    return {
        "intent_plan_json": json.dumps(_prompt_intent_plan(payload), ensure_ascii=False, indent=2),
        "source_schema_json": json.dumps(schemas, ensure_ascii=False, indent=2),
        "source_preview_json": json.dumps(previews, ensure_ascii=False, indent=2),
        "function_case_selection_json": json.dumps(_function_case_selection(payload), ensure_ascii=False, indent=2),
        "output_contract_json": json.dumps(_prompt_output_contract(payload), ensure_ascii=False, indent=2),
    }


# 함수 설명: `_prompt_intent_plan()`은 executor 전용 카탈로그 설정과 별도 출력 계약을 제거해 pandas LLM 입력 token 중복을 줄입니다.
def _prompt_intent_plan(payload: dict[str, Any]) -> dict[str, Any]:
    plan = deepcopy(payload.get("intent_plan")) if isinstance(payload.get("intent_plan"), dict) else {}
    plan.pop("output_contract", None)
    jobs = plan.get("retrieval_jobs") if isinstance(plan.get("retrieval_jobs"), list) else []
    compact_jobs: list[Any] = []
    for job in jobs:
        if not isinstance(job, dict):
            compact_jobs.append(job)
            continue
        compact_jobs.append(
            {
                str(key): value
                for key, value in job.items()
                if str(key) not in PROMPT_INTERNAL_JOB_KEYS
            }
        )
    if jobs:
        plan["retrieval_jobs"] = compact_jobs
    return plan


# 함수 설명: `_prompt_output_contract()`는 폐기된 상세 계약 key를 제거한 canonical 출력 계약만 pandas prompt에 전달합니다.
def _prompt_output_contract(payload: dict[str, Any]) -> dict[str, Any]:
    plan = payload.get("intent_plan") if isinstance(payload.get("intent_plan"), dict) else {}
    contract = plan.get("output_contract") if isinstance(plan.get("output_contract"), dict) else {}
    return {
        str(key): deepcopy(value)
        for key, value in contract.items()
        if str(key) not in RETIRED_OUTPUT_CONTRACT_KEYS
    }


# 함수 설명: `_payload()`는 Langflow Data/Message 또는 일반 dict 입력에서 안전한 dict 페이로드 복사본을 꺼냅니다.
def _payload(value: Any) -> dict[str, Any]:
    data = getattr(value, "data", value)
    return deepcopy(data) if isinstance(data, dict) else {}


# 함수 설명: `_source_schemas()`는 schemas 정보를 현재 질문과 응답 계약에 맞는 dict 또는 행으로 구성합니다.
def _source_schemas(payload: dict[str, Any]) -> dict[str, list[str]]:
    schemas: dict[str, list[str]] = {}
    for source in payload.get("source_results", []) if isinstance(payload.get("source_results"), list) else []:
        if not isinstance(source, dict):
            continue
        alias = str(source.get("source_alias") or source.get("dataset_key") or "").strip()
        columns = _string_list(source.get("columns"))
        if alias and columns:
            schemas[alias] = columns
    for alias, rows in payload.get("runtime_sources", {}).items() if isinstance(payload.get("runtime_sources"), dict) else []:
        if not isinstance(rows, list):
            continue
        row_columns = sorted({str(column) for row in rows[:20] if isinstance(row, dict) for column in row})
        if row_columns:
            schemas[str(alias)] = row_columns
        else:
            schemas.setdefault(str(alias), [])
    return schemas


# 함수 설명: `_string_list()`는 여러 형태의 입력에서 비어 있지 않은 문자열만 뽑아 중복 없는 목록으로 정리합니다.
def _string_list(value: Any) -> list[str]:
    return [str(item) for item in value if str(item or "").strip()] if isinstance(value, list) else []


# 함수 설명: `_function_case_selection()`는 Function Case·selection 관련 정보를 계산·선별해 후속 분석 또는 표시 단계에 전달합니다.
def _function_case_selection(payload: dict[str, Any]) -> dict[str, Any]:
    plan = payload.get("intent_plan") if isinstance(payload.get("intent_plan"), dict) else {}
    steps = plan.get("pandas_execution_plan") if isinstance(plan.get("pandas_execution_plan"), list) else []
    selected_steps = [
        deepcopy(step)
        for step in steps
        if isinstance(step, dict)
        and str(step.get("operation") or "").strip() == "apply_pandas_function_case"
    ]
    selected_cases = _selected_function_cases(plan, selected_steps)
    return {
        "selected_cases": selected_cases,
        "selected_steps": selected_steps,
        "available_helpers": _helpers_from_selected_cases(selected_cases),
    }


# 함수 설명: `_helpers_from_selected_cases()`는 선택 Function Case 항목에서 pandas 프롬프트에 제공할 helper 이름만 추출합니다.
def _helpers_from_selected_cases(selected_cases: list[dict[str, Any]]) -> list[dict[str, Any]]:
    helpers = []
    for item in selected_cases:
        if not isinstance(item, dict):
            continue
        name = str(item.get("function_name") or "").strip()
        if not name or any(helper.get("function_name") == name for helper in helpers):
            continue
        helper = {"function_name": name}
        for key in (
            "signature",
            "description",
            "usage_rule",
            "default_token_columns",
        ):
            if item.get(key) not in (None, "", [], {}):
                helper[key] = deepcopy(item.get(key))
        helpers.append(helper)
    return helpers


# 함수 설명: `_selected_function_cases()`는 의도 계획에서 실제 pandas 실행에 선택된 Function Case 항목만 정리합니다.
def _selected_function_cases(plan: dict[str, Any], selected_steps: list[dict[str, Any]]) -> list[dict[str, Any]]:
    cases = []
    single = plan.get("pandas_function_case")
    if isinstance(single, dict) and single:
        cases.append(deepcopy(single))
    for item in plan.get("pandas_function_cases", []) if isinstance(plan.get("pandas_function_cases"), list) else []:
        if isinstance(item, dict) and item not in cases:
            cases.append(deepcopy(item))
    for step in selected_steps:
        item = {
            "key": step.get("function_case_key", ""),
            "function_name": step.get("function_name", ""),
            "input_text": step.get("input_text", ""),
            "source_alias": step.get("source_alias", ""),
        }
        if item not in cases:
            cases.append(item)
    return _dedupe_cases(cases)


# 함수 설명: `_dedupe_cases()`는 cases의 중복을 제거하고 최초 등장 순서를 유지합니다.
def _dedupe_cases(cases: list[dict[str, Any]]) -> list[dict[str, Any]]:
    deduped: list[dict[str, Any]] = []
    seen: set[tuple[str, str, str, str]] = set()
    for item in cases:
        marker = (
            str(item.get("function_name") or ""),
            str(item.get("key") or item.get("function_case_key") or ""),
            str(item.get("input_text") or ""),
            str(item.get("source_alias") or ""),
        )
        if marker in seen:
            continue
        seen.add(marker)
        deduped.append(deepcopy(item))
    return deduped


# Langflow 컴포넌트 클래스: inputs/outputs가 캔버스 포트와 JSON edge 계약을 정의합니다.
# 실제 업무 규칙은 위의 주요 함수에 두어 UI 실행과 단위 테스트가 같은 로직을 사용합니다.
class PandasVariablesBuilder(Component):
    display_name = "15 pandas 변수 생성기"
    description = "Langflow 프롬프트 템플릿과 에이전트/LLM에 연결할 pandas 코드 생성 변수를 제공합니다. function case 선택 정보는 16번 Prompt Template에 연결하고, 실제 함수 코드는 별도 입력으로 넣습니다."
    inputs = [DataInput(name="payload", display_name="페이로드", required=True)]
    outputs = [
        Output(name="intent_plan_json", display_name="의도 계획 JSON", method="build_intent_plan_json", types=["Message"], group_outputs=True),
        Output(name="source_schema_json", display_name="소스 스키마 JSON", method="build_source_schema_json", types=["Message"], group_outputs=True),
        Output(name="source_preview_json", display_name="소스 미리보기 JSON", method="build_source_preview_json", types=["Message"], group_outputs=True),
        Output(name="function_case_selection_json", display_name="Function Case 선택 정보 JSON", method="build_function_case_selection_json", types=["Message"], group_outputs=True),
        Output(name="output_contract_json", display_name="출력 계약 JSON", method="build_output_contract_json", types=["Message"], group_outputs=True),
    ]

    # 함수 설명: `_variables_once()`는 다섯 Prompt 변수가 같은 runtime source를 반복 deepcopy·JSON 변환하지 않도록 한 번만 계산합니다.
    def _variables_once(self) -> dict[str, Any]:
        payload = getattr(self, "payload", None)
        cache_key = id(payload)
        if getattr(self, "_variables_cache_key", None) != cache_key:
            self._variables_cache_key = cache_key
            self._variables_cache = build_variables(payload)
        return self._variables_cache

    # Langflow 출력 함수: '의도 계획 JSON (intent_plan_json)' 포트가 요청될 때 실행됩니다.
    # 핵심 처리 결과를 Langflow Data/Message 형식으로 감싸 다음 노드에 전달합니다.
    def build_intent_plan_json(self) -> Message:
        return Message(text=self._variables_once()["intent_plan_json"])

    # Langflow 출력 함수: '소스 스키마 JSON (source_schema_json)' 포트가 요청될 때 실행됩니다.
    # 핵심 처리 결과를 Langflow Data/Message 형식으로 감싸 다음 노드에 전달합니다.
    def build_source_schema_json(self) -> Message:
        return Message(text=self._variables_once()["source_schema_json"])

    # Langflow 출력 함수: '소스 미리보기 JSON (source_preview_json)' 포트가 요청될 때 실행됩니다.
    # 핵심 처리 결과를 Langflow Data/Message 형식으로 감싸 다음 노드에 전달합니다.
    def build_source_preview_json(self) -> Message:
        return Message(text=self._variables_once()["source_preview_json"])

    # Langflow 출력 함수: 'Function Case 선택 정보 JSON (function_case_selection_json)' 포트가 요청될 때 실행됩니다.
    # 핵심 처리 결과를 Langflow Data/Message 형식으로 감싸 다음 노드에 전달합니다.
    def build_function_case_selection_json(self) -> Message:
        return Message(text=self._variables_once()["function_case_selection_json"])

    # Langflow 출력 함수: '출력 계약 JSON (output_contract_json)' 포트가 요청될 때 실행됩니다.
    # 핵심 처리 결과를 Langflow Data/Message 형식으로 감싸 다음 노드에 전달합니다.
    def build_output_contract_json(self) -> Message:
        return Message(text=self._variables_once()["output_contract_json"])

# -*- coding: utf-8 -*-
# =============================================================================
# 컴포넌트 개요: 18 답변 생성 변수 생성기
# 역할: Langflow 프롬프트 템플릿과 에이전트/LLM에 연결할 답변 생성 변수를 제공합니다.
# 주요 입력: 페이로드 (payload) · 필수
# 주요 출력: 사용자 질문 (question), 결과 요약 JSON (result_summary_json), 적용 범위 JSON (applied_scope_json), 답변 컨텍스트 JSON
#        (answer_context_json), 경고/오류 JSON (warnings_errors_json)
# 처리 흐름: 최종 답변 LLM에 필요한 질문·결과 요약·적용 조건·근거·경고만 안전한 크기로 압축합니다.
# 유지보수 포인트: inputs/outputs의 name은 Langflow JSON edge 계약이므로 변경 시 모든 Flow JSON을 재생성하고 source sync 검증을 실행해야 합니다.
# =============================================================================

from __future__ import annotations

import json
from copy import deepcopy
from datetime import date, datetime
from decimal import Decimal
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, Output
from lfx.schema.message import Message

# 주요 함수: LLM 프롬프트에 연결할 변수만 선별하고 JSON-safe 문자열 또는 dict로 정리합니다.
# Langflow 클래스와 단위 테스트가 같은 업무 규칙을 쓰도록 일반 Python 값 중심으로 처리합니다.
def build_variables(payload_value: Any) -> dict[str, Any]:
    payload = _payload(payload_value)
    return {
        "question": payload.get("request", {}).get("question", ""),
        "result_summary_json": _json_dumps(payload.get("data", {})),
        "applied_scope_json": _json_dumps(_compact_applied_scope(payload)),
        "answer_context_json": _json_dumps(_answer_context(payload)),
        "warnings_errors_json": _json_dumps({"warnings": payload.get("trace", {}).get("warnings", []), "errors": payload.get("trace", {}).get("errors", [])}),
    }


# 함수 설명: `_payload()`는 Langflow Data/Message 또는 일반 dict 입력에서 안전한 dict 페이로드 복사본을 꺼냅니다.
def _payload(value: Any) -> dict[str, Any]:
    data = getattr(value, "data", value)
    return deepcopy(data) if isinstance(data, dict) else {}


# 함수 설명: `_compact_applied_scope()`는 적용 조건·분석 범위에서 후속 단계에 필요한 정보만 남겨 payload와 token 크기를 줄입니다.
def _compact_applied_scope(payload: dict[str, Any]) -> dict[str, Any]:
    plan = payload.get("intent_plan") if isinstance(payload.get("intent_plan"), dict) else {}
    inspection = payload.get("trace", {}).get("inspection", {}) if isinstance(payload.get("trace"), dict) else {}
    if not isinstance(inspection, dict):
        inspection = {}

    retrieval_jobs = plan.get("retrieval_jobs") if isinstance(plan.get("retrieval_jobs"), list) else []
    pandas_plan = plan.get("pandas_execution_plan") if isinstance(plan.get("pandas_execution_plan"), list) else []
    result: dict[str, Any] = {
        "intent": _omit_empty(
            {
                "analysis_kind": plan.get("analysis_kind") or _dict(inspection.get("intent")).get("analysis_kind"),
                "retrieval_job_count": len(retrieval_jobs),
                "pandas_step_count": len(pandas_plan),
                "metadata_ref_count": len(payload.get("metadata_refs", [])) if isinstance(payload.get("metadata_refs"), list) else 0,
            }
        ),
        "retrieval": [_compact_source_result(item) for item in _list(payload.get("source_results"))],
        "pandas_execution": _compact_pandas_execution(payload, _dict(inspection.get("pandas_execution"))),
    }
    result_store = _compact_result_store(_dict(inspection.get("result_store")))
    if result_store:
        result["result_store"] = result_store
    return result


# 함수 설명: `_compact_source_result()`는 데이터 소스·결과에서 후속 단계에 필요한 정보만 남겨 payload와 token 크기를 줄입니다.
def _compact_source_result(value: Any) -> dict[str, Any]:
    source = _dict(value)
    source_execution = _dict(source.get("source_execution"))
    return _omit_empty(
        {
            "source_alias": source.get("source_alias"),
            "dataset_key": source.get("dataset_key"),
            "source_type": source.get("source_type"),
            "status": source.get("status"),
            "row_count": source.get("row_count"),
            "applied_params": source.get("applied_params"),
            "pandas_filters": source.get("pandas_filters"),
            "used_dummy_data": source_execution.get("used_dummy_data"),
            "adapter": source_execution.get("adapter"),
            "params_applied_in_retriever": source_execution.get("params_applied_in_retriever"),
            "filters_applied_in_retriever": source_execution.get("filters_applied_in_retriever"),
        }
    )


# 함수 설명: `_compact_pandas_execution()`는 pandas 실행·execution에서 후속 단계에 필요한 정보만 남겨 payload와 token 크기를 줄입니다.
def _compact_pandas_execution(payload: dict[str, Any], pandas_execution: dict[str, Any]) -> dict[str, Any]:
    analysis = payload.get("analysis") if isinstance(payload.get("analysis"), dict) else {}
    execution_result = _dict(pandas_execution.get("execution_result"))
    return _omit_empty(
        {
            "stage": pandas_execution.get("stage"),
            "status": pandas_execution.get("status") or analysis.get("status"),
            "row_count": execution_result.get("row_count", analysis.get("row_count")),
            "columns": execution_result.get("columns", analysis.get("columns")),
            "used_helpers": pandas_execution.get("used_helpers", analysis.get("used_helpers")),
            "pandas_filter_plan": pandas_execution.get("pandas_filter_plan"),
            "error": _compact_error(pandas_execution.get("error") or analysis.get("error")),
        }
    )


# 함수 설명: `_compact_error()`는 오류에서 후속 단계에 필요한 정보만 남겨 payload와 token 크기를 줄입니다.
def _compact_error(value: Any) -> Any:
    error = _dict(value)
    if not error:
        return None
    return _omit_empty({"type": error.get("type"), "message": error.get("message")})


# 함수 설명: `_compact_result_store()`는 결과·store에서 후속 단계에 필요한 정보만 남겨 payload와 token 크기를 줄입니다.
def _compact_result_store(result_store: dict[str, Any]) -> dict[str, Any]:
    return _omit_empty(
        {
            "status": result_store.get("status"),
            "data_ref": result_store.get("data_ref"),
            "ttl_hours": result_store.get("ttl_hours"),
            "expires_at": result_store.get("expires_at"),
        }
    )


# 함수 설명: `_answer_context()`는 문맥에서 현재 단계가 사용할 필드만 추출해 표준 구조로 정리합니다.
def _answer_context(payload: dict[str, Any]) -> dict[str, Any]:
    analysis = payload.get("analysis") if isinstance(payload.get("analysis"), dict) else {}
    pandas_execution = _dict(_dict(payload.get("trace")).get("inspection")).get("pandas_execution")
    pandas_execution = _dict(pandas_execution)
    data = payload.get("data") if isinstance(payload.get("data"), dict) else {}
    step_outputs = _list(analysis.get("step_outputs")) or _list(pandas_execution.get("step_outputs"))
    function_case_results = _list(analysis.get("function_case_results")) or _list(pandas_execution.get("function_case_results"))
    rows = _list(data.get("rows"))
    columns = _list(data.get("columns")) or _columns_from_rows(rows)
    metric_columns = _metric_columns(columns, rows)
    return {
        "number_display_policy": {
            "under_10000": "comma_full_number",
            "gte_10000": "k_unit",
            "display_only": True,
        },
        "result_shape": _omit_empty(
            {
                "row_count": data.get("row_count", analysis.get("row_count")),
                "columns": columns or analysis.get("columns"),
            }
        ),
        "applied_criteria": _applied_criteria(payload),
        "result_interpretation_hints": _omit_empty(
            {
                "is_empty_result": _int(data.get("row_count"), len(rows)) == 0 and not rows,
                "has_zero_values": _has_zero_values(rows),
                "primary_metric_columns": metric_columns,
                "primary_dimension_columns": _dimension_columns(columns, metric_columns),
            }
        ),
        "step_outputs": deepcopy(step_outputs),
        "function_case_results": deepcopy(function_case_results),
        "next_question_candidates": _next_question_candidates(data),
    }


# 함수 설명: `_applied_criteria()`는 조회 작업과 pandas 계획에서 실제 적용된 날짜·제품·공정·지표 조건을 구성합니다.
def _applied_criteria(payload: dict[str, Any]) -> dict[str, Any]:
    plan = _dict(payload.get("intent_plan"))
    required_params: dict[str, Any] = {}
    analysis_filters: dict[str, Any] = {}
    datasets: list[dict[str, Any]] = []
    for job in _list(plan.get("retrieval_jobs")):
        if not isinstance(job, dict):
            continue
        alias = str(job.get("source_alias") or job.get("dataset_key") or "").strip()
        dataset_key = str(job.get("dataset_key") or "").strip()
        if dataset_key or alias:
            datasets.append(_omit_empty({"dataset_key": dataset_key, "source_alias": alias, "source_type": job.get("source_type")}))
        params = _dict(job.get("required_params"))
        if params:
            required_params[alias or dataset_key or f"job_{len(required_params) + 1}"] = deepcopy(params)
        filters = _dict(job.get("filters"))
        if filters:
            analysis_filters[alias or dataset_key or f"job_{len(analysis_filters) + 1}"] = deepcopy(filters)
    for source in _list(payload.get("source_results")):
        if not isinstance(source, dict):
            continue
        alias = str(source.get("source_alias") or source.get("dataset_key") or "").strip()
        dataset_key = str(source.get("dataset_key") or "").strip()
        params = _dict(source.get("applied_params"))
        if params:
            required_params[alias or dataset_key or f"source_{len(required_params) + 1}"] = deepcopy(params)
        filters = _dict(source.get("pandas_filters")) or _dict(source.get("applied_filters"))
        if filters:
            analysis_filters[alias or dataset_key or f"source_{len(analysis_filters) + 1}"] = deepcopy(filters)
    return _omit_empty(
        {
            "required_params": required_params,
            "analysis_filters": analysis_filters,
            "datasets": _dedupe_dicts(datasets),
            "group_by": _group_by_columns(_list(plan.get("pandas_execution_plan"))),
        }
    )


# 함수 설명: `_columns_from_rows()`는 행 목록의 key 등장 순서를 유지하면서 결과 테이블의 컬럼 목록을 계산합니다.
def _columns_from_rows(rows: list[Any]) -> list[str]:
    columns: list[str] = []
    for row in rows:
        if not isinstance(row, dict):
            continue
        for key in row:
            text = str(key)
            if text not in columns:
                columns.append(text)
    return columns


# 함수 설명: `_has_zero_values()`는 입력값이 ZERO·값 조건에 해당하는지 부작용 없이 bool로 판정합니다.
def _has_zero_values(rows: list[Any]) -> bool:
    for row in rows:
        if not isinstance(row, dict):
            continue
        for value in row.values():
            if isinstance(value, bool):
                continue
            try:
                if float(value) == 0:
                    return True
            except Exception:
                continue
    return False


# 함수 설명: `_metric_columns()`는 결과 컬럼 중 수량·실적·비율처럼 답변 지표로 사용할 컬럼을 선별합니다.
def _metric_columns(columns: list[Any], rows: list[Any]) -> list[str]:
    result: list[str] = []
    for column in columns:
        text = str(column)
        if _column_has_numeric_value(rows, text):
            result.append(text)
    return result


# 함수 설명: `_dimension_columns()`는 결과 컬럼 중 제품·공정·장비처럼 그룹 기준으로 사용할 컬럼을 선별합니다.
def _dimension_columns(columns: list[Any], metric_columns: list[str]) -> list[str]:
    metric_set = set(metric_columns)
    return [str(column) for column in columns if str(column) not in metric_set]


# 함수 설명: `_column_has_numeric_value()`는 HAS·numeric·값 관련 정보를 계산·선별해 후속 분석 또는 표시 단계에 전달합니다.
def _column_has_numeric_value(rows: list[Any], column: str) -> bool:
    for row in rows:
        if not isinstance(row, dict):
            continue
        value = row.get(column)
        if value is None or isinstance(value, bool):
            continue
        if isinstance(value, str):
            continue
        try:
            number = float(value)
        except Exception:
            continue
        if number != number:
            continue
        return True
    return False


# 함수 설명: `_group_by_columns()`는 의도 계획의 pandas 단계에서 실제 그룹 기준 컬럼을 추출합니다.
def _group_by_columns(pandas_plan: list[Any]) -> list[str]:
    columns: list[str] = []
    for step in pandas_plan:
        if not isinstance(step, dict):
            continue
        for key in ("groupby_columns", "group_by", "group_by_columns", "group_columns"):
            value = step.get(key)
            if isinstance(value, list):
                for item in value:
                    text = str(item or "").strip()
                    if text and text not in columns:
                        columns.append(text)
            elif isinstance(value, str) and value.strip() and value.strip() not in columns:
                columns.append(value.strip())
    return columns


# 함수 설명: `_next_question_candidates()`는 question·후보 관련 정보를 계산·선별해 후속 분석 또는 표시 단계에 전달합니다.
def _next_question_candidates(data: dict[str, Any]) -> list[str]:
    row_count = _int(data.get("row_count"), len(_list(data.get("rows"))))
    if row_count <= 0:
        return ["조건을 넓혀서 다시 조회할까요?"]
    return ["이 결과를 제품별 또는 공정별로 더 나눠볼까요?", "원본 데이터 기준으로 상세 행을 확인할까요?"]


# 함수 설명: `_dict()`는 입력값이 dict인지 확인하고 아니면 빈 dict를 반환해 후속 key 접근 오류를 막습니다.
def _dict(value: Any) -> dict[str, Any]:
    return value if isinstance(value, dict) else {}


# 함수 설명: `_list()`는 입력값을 list로 정규화하고 목록이 아닌 값은 안전한 기본 목록으로 바꿉니다.
def _list(value: Any) -> list[Any]:
    return value if isinstance(value, list) else []


# 함수 설명: `_int()`는 문자열이나 숫자 입력을 정수로 변환하고 실패하면 안전한 기본값을 사용합니다.
def _int(value: Any, default: int = 0) -> int:
    try:
        return int(value)
    except Exception:
        return default


# 함수 설명: `_omit_empty()`는 dict에서 빈 문자열·빈 목록·None 항목을 제거해 전달 payload를 작게 유지합니다.
def _omit_empty(value: dict[str, Any]) -> dict[str, Any]:
    return {key: item for key, item in value.items() if _has_compact_value(item)}


# 함수 설명: `_dedupe_dicts()`는 dicts의 중복을 제거하고 최초 등장 순서를 유지합니다.
def _dedupe_dicts(items: list[dict[str, Any]]) -> list[dict[str, Any]]:
    seen: set[str] = set()
    result: list[dict[str, Any]] = []
    for item in items:
        signature = json.dumps(item, ensure_ascii=False, sort_keys=True, default=str)
        if signature in seen:
            continue
        seen.add(signature)
        result.append(item)
    return result


# 함수 설명: `_has_compact_value()`는 입력값이 compact·값 조건에 해당하는지 부작용 없이 bool로 판정합니다.
def _has_compact_value(value: Any) -> bool:
    if value is None:
        return False
    if isinstance(value, str):
        return bool(value)
    if isinstance(value, (list, tuple, set, dict)):
        return bool(value)
    return True


# 함수 설명: `_json_dumps()`는 datetime·Decimal 같은 값까지 JSON-safe 형태로 바꾼 뒤 문자열로 직렬화합니다.
def _json_dumps(value: Any) -> str:
    return json.dumps(_json_ready(value), ensure_ascii=False, indent=2)


# 함수 설명: `_json_ready()`는 datetime·Decimal·NaN 등 JSON이 직접 표현하지 못하는 값을 안전한 기본형으로 재귀 변환합니다.
def _json_ready(value: Any) -> Any:
    if value is None or type(value) in (str, int, bool):
        return value
    if type(value) is float:
        return None if value != value or value in (float("inf"), -float("inf")) else value
    if isinstance(value, (datetime, date)):
        return value.isoformat()
    if isinstance(value, Decimal):
        return float(value)
    item = getattr(value, "item", None)
    if callable(item):
        try:
            return _json_ready(item())
        except Exception:
            pass
    if isinstance(value, dict):
        return {str(key): _json_ready(item_value) for key, item_value in value.items()}
    if isinstance(value, (list, tuple, set)):
        return [_json_ready(item_value) for item_value in value]
    try:
        if value != value:
            return None
    except Exception:
        pass
    return str(value)


# Langflow 컴포넌트 클래스: inputs/outputs가 캔버스 포트와 JSON edge 계약을 정의합니다.
# 실제 업무 규칙은 위의 주요 함수에 두어 UI 실행과 단위 테스트가 같은 로직을 사용합니다.
class AnswerVariablesBuilder(Component):
    display_name = "18 답변 생성 변수 생성기"
    description = "Langflow 프롬프트 템플릿과 에이전트/LLM에 연결할 답변 생성 변수를 제공합니다."
    inputs = [DataInput(name="payload", display_name="페이로드", required=True)]
    outputs = [
        Output(name="question", display_name="사용자 질문", method="build_question", types=["Message"], group_outputs=True),
        Output(name="result_summary_json", display_name="결과 요약 JSON", method="build_result_summary", types=["Message"], group_outputs=True),
        Output(name="applied_scope_json", display_name="적용 범위 JSON", method="build_applied_scope", types=["Message"], group_outputs=True),
        Output(name="answer_context_json", display_name="답변 컨텍스트 JSON", method="build_answer_context", types=["Message"], group_outputs=True),
        Output(name="warnings_errors_json", display_name="경고/오류 JSON", method="build_warnings_errors", types=["Message"], group_outputs=True),
    ]

    # 함수 설명: `_variables_once()`는 결과 요약·적용 범위·경고 변수를 동일 payload에서 한 번만 계산해 대용량 행 복사를 줄입니다.
    def _variables_once(self) -> dict[str, Any]:
        payload = getattr(self, "payload", None)
        cache_key = id(payload)
        if getattr(self, "_variables_cache_key", None) != cache_key:
            self._variables_cache_key = cache_key
            self._variables_cache = build_variables(payload)
        return self._variables_cache

    # Langflow 출력 함수: '사용자 질문 (question)' 포트가 요청될 때 실행됩니다.
    # 핵심 처리 결과를 Langflow Data/Message 형식으로 감싸 다음 노드에 전달합니다.
    def build_question(self) -> Message:
        return Message(text=self._variables_once()["question"])

    # Langflow 출력 함수: '결과 요약 JSON (result_summary_json)' 포트가 요청될 때 실행됩니다.
    # 핵심 처리 결과를 Langflow Data/Message 형식으로 감싸 다음 노드에 전달합니다.
    def build_result_summary(self) -> Message:
        return Message(text=self._variables_once()["result_summary_json"])

    # Langflow 출력 함수: '적용 범위 JSON (applied_scope_json)' 포트가 요청될 때 실행됩니다.
    # 핵심 처리 결과를 Langflow Data/Message 형식으로 감싸 다음 노드에 전달합니다.
    def build_applied_scope(self) -> Message:
        return Message(text=self._variables_once()["applied_scope_json"])

    # Langflow 출력 함수: '답변 컨텍스트 JSON (answer_context_json)' 포트가 요청될 때 실행됩니다.
    # 핵심 처리 결과를 Langflow Data/Message 형식으로 감싸 다음 노드에 전달합니다.
    def build_answer_context(self) -> Message:
        return Message(text=self._variables_once()["answer_context_json"])

    # Langflow 출력 함수: '경고/오류 JSON (warnings_errors_json)' 포트가 요청될 때 실행됩니다.
    # 핵심 처리 결과를 Langflow Data/Message 형식으로 감싸 다음 노드에 전달합니다.
    def build_warnings_errors(self) -> Message:
        return Message(text=self._variables_once()["warnings_errors_json"])

# -*- coding: utf-8 -*-
# =============================================================================
# 컴포넌트 개요: 20 답변 응답 생성기
# 역할: Langflow 에이전트/LLM 답변 문장과 결정된 데이터를 합쳐 페이로드를 완성합니다.
# 주요 입력: 페이로드 (payload) · 필수, 답변 문장 (answer_text)
# 주요 출력: 페이로드 출력 (payload_out)
# 처리 흐름: LLM 답변과 결정론적 분석 결과를 합쳐 answer sections, evidence, 현재 상태와 후속 상태를 구성합니다.
# 유지보수 포인트: inputs/outputs의 name은 Langflow JSON edge 계약이므로 변경 시 모든 Flow JSON을 재생성하고 source sync 검증을 실행해야 합니다.
# =============================================================================

from __future__ import annotations

import json
import re
from math import isclose
from copy import deepcopy
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, MessageTextInput, Output
from lfx.schema.data import Data

TABLE_PREVIEW_LIMIT = 10


# 주요 함수: LLM 문장과 분석 결과를 합쳐 최종 구조화 답변과 다음 상태를 만듭니다.
# Langflow 클래스와 단위 테스트가 같은 업무 규칙을 쓰도록 일반 Python 값 중심으로 처리합니다.
def build_answer_response(payload_value: Any, answer_text: Any = "") -> dict[str, Any]:
    payload = _payload(payload_value)
    received_structured_answer = _answer_payload(answer_text)
    received_message = (
        _answer_text_from_dict(received_structured_answer)
        if received_structured_answer
        else _answer_text(answer_text)
    ).strip()
    blocked = _execution_blocked(payload)
    structured_answer = {} if blocked else received_structured_answer
    message = str(payload.get("answer_message") or "").strip() if blocked else received_message
    if not message:
        message = str(payload.get("answer_message") or "").strip()
    if not message:
        row_count = payload.get("data", {}).get("row_count", 0)
        message = f"분석 결과 {row_count}건을 확인했습니다." if payload.get("analysis", {}).get("status") == "ok" else "분석을 완료하지 못했습니다. trace의 오류를 확인해 주세요."
    next_payload = payload
    next_payload.setdefault("trace", {}).setdefault("inspection", {})["answer_model_response"] = {
        "stage": "20_answer_response_builder",
        "received": bool(received_message or received_structured_answer),
        "used": not blocked and bool(received_message or received_structured_answer),
        "ignored": blocked and bool(received_message or received_structured_answer),
        "policy": "ignore" if blocked else "use",
    }
    message, grounding = _ground_answer_message(next_payload, message)
    if grounding:
        trace = next_payload.setdefault("trace", {})
        trace.setdefault("warnings", []).append(
            {
                "type": "answer_value_grounded",
                "message": "LLM 답변의 수치가 실제 결과 행과 일치하지 않아 결과 행 기준 문장으로 교정했습니다.",
            }
        )
        trace.setdefault("inspection", {})["answer_grounding"] = grounding
    next_payload["answer_message"] = message
    next_payload["answer_sections"] = _build_answer_sections(next_payload, message, _dict(structured_answer.get("answer_sections")))
    next_payload["state"] = _build_next_turn_state(next_payload)
    return next_payload


# 함수 설명: `_execution_blocked()`는 필수 조회 실패 시 기본 Language Model 응답을 최종 답변에 사용하지 않도록 판정합니다.
def _execution_blocked(payload: dict[str, Any]) -> bool:
    gate = _dict(payload.get("execution_gate"))
    return str(gate.get("status") or "").strip().lower() == "blocked"


# 함수 설명: `_ground_answer_message()`는 LLM 문장에 결과 행으로 확인되지 않는 수치가 있을 때 재호출 없이 결정론적으로 교정합니다.
def _ground_answer_message(payload: dict[str, Any], message: str) -> tuple[str, dict[str, Any]]:
    analysis = _dict(payload.get("analysis"))
    data = _dict(payload.get("data"))
    rows = _list(data.get("rows"))
    if analysis.get("status") != "ok" or not rows or not message:
        return message, {}

    unsupported = _unsupported_numeric_claims(payload, message)
    if not unsupported:
        return message, {}

    grounded_message = _authoritative_result_message(data)
    if not grounded_message:
        return message, {}
    return grounded_message, {
        "stage": "20_answer_response_builder",
        "status": "corrected",
        "unsupported_numeric_claims": unsupported,
        "policy": "deterministic_data_rows",
    }


# 함수 설명: `_unsupported_numeric_claims()`는 질문 조건이나 실제 결과에 없는 LLM 수치 주장만 선별합니다.
def _unsupported_numeric_claims(payload: dict[str, Any], message: str) -> list[str]:
    known_values = _known_numeric_values(payload)
    unsupported: list[str] = []
    for raw, number in _numeric_claims(message):
        claim_values = [number, number * 100] if raw.endswith("%") else [number]
        if any(
            isclose(claim, known, rel_tol=1e-9, abs_tol=1e-9)
            for claim in claim_values
            for known in known_values
        ):
            continue
        unsupported.append(raw)
    return unsupported


# 함수 설명: `_known_numeric_values()`는 결과 행과 질문 조건에서 답변에 나타나도 되는 수치 집합을 구성합니다.
def _known_numeric_values(payload: dict[str, Any]) -> list[float]:
    data = _dict(payload.get("data"))
    values: list[float] = []
    for row in _list(data.get("rows")):
        if not isinstance(row, dict):
            continue
        for value in row.values():
            values.extend(_numbers_from_value(value))
    values.extend(_numbers_from_value(data.get("row_count")))
    values.extend(_numbers_from_value(_dict(payload.get("request"))))
    values.extend(_numbers_from_value(_dict(payload.get("intent_plan")).get("retrieval_jobs")))
    return _dedupe_numbers(values)


# 함수 설명: `_numbers_from_value()`는 숫자와 날짜형 문자열을 재귀적으로 읽어 비교 가능한 실수 값으로 바꿉니다.
def _numbers_from_value(value: Any) -> list[float]:
    if value is None or isinstance(value, bool):
        return []
    if isinstance(value, (int, float)):
        try:
            number = float(value)
        except Exception:
            return []
        return [] if number != number else [number]
    if isinstance(value, dict):
        return [number for item in value.values() for number in _numbers_from_value(item)]
    if isinstance(value, (list, tuple, set)):
        return [number for item in value for number in _numbers_from_value(item)]
    text = str(value or "").strip()
    if not text:
        return []
    numbers = [number for _, number in _numeric_claims(text)]
    for date_text in re.findall(r"(?<!\d)(\d{8})(?!\d)", text):
        numbers.extend([float(date_text[:4]), float(date_text[4:6]), float(date_text[6:8])])
    return numbers


# 함수 설명: `_numeric_claims()`는 제품 코드 안의 숫자는 제외하고 일반 수치·K/M 단위·퍼센트 표현을 파싱합니다.
def _numeric_claims(text: str) -> list[tuple[str, float]]:
    pattern = re.compile(r"(?<![A-Za-z0-9_/.-])([+-]?\d[\d,]*(?:\.\d+)?)([KkMm]?)(%)?(?![A-Za-z0-9_/.-])")
    claims: list[tuple[str, float]] = []
    for match in pattern.finditer(str(text or "")):
        raw = match.group(0).strip()
        try:
            number = float(match.group(1).replace(",", ""))
        except Exception:
            continue
        unit = match.group(2).lower()
        if unit == "k":
            number *= 1000
        elif unit == "m":
            number *= 1_000_000
        if match.group(3):
            number /= 100
        claims.append((raw, number))
    return claims


# 함수 설명: `_authoritative_result_message()`는 실제 data.rows만 이용해 수치 모순이 없는 짧은 대체 문장을 만듭니다.
def _authoritative_result_message(data: dict[str, Any]) -> str:
    rows = [row for row in _list(data.get("rows")) if isinstance(row, dict)]
    if not rows:
        return ""
    columns = _string_list(data.get("columns")) or _columns_from_rows(rows)
    first_row = rows[0]
    facts = []
    for column in columns[:6]:
        if column not in first_row:
            continue
        value = _display_value(first_row.get(column))
        facts.append(f"{column}={value}")
    row_count = _int(data.get("row_count"), len(rows))
    if row_count <= 1:
        return f"분석 결과 {', '.join(facts)}입니다." if facts else "분석 결과 1건입니다."
    prefix = f"분석 결과 총 {row_count:,}건입니다."
    return f"{prefix} 첫 번째 결과는 {', '.join(facts)}입니다." if facts else prefix


# 함수 설명: `_dedupe_numbers()`는 부동소수 비교 오차를 고려해 숫자 목록의 중복을 제거합니다.
def _dedupe_numbers(values: list[float]) -> list[float]:
    result: list[float] = []
    for value in values:
        if not any(isclose(value, existing, rel_tol=1e-12, abs_tol=1e-12) for existing in result):
            result.append(value)
    return result


# 함수 설명: `_payload()`는 Langflow Data/Message 또는 일반 dict 입력에서 안전한 dict 페이로드 복사본을 꺼냅니다.
def _payload(value: Any) -> dict[str, Any]:
    data = getattr(value, "data", value)
    return deepcopy(data) if isinstance(data, dict) else {}


# 함수 설명: `_answer_text()`는 문자열에서 현재 단계가 사용할 필드만 추출해 표준 구조로 정리합니다.
def _answer_text(value: Any) -> str:
    if isinstance(value, dict):
        text = _answer_text_from_dict(value)
        return text if text else json.dumps(value, ensure_ascii=False, default=str)

    text = _message_text(value).strip()
    parsed = _json_text(text)
    if parsed:
        parsed_text = _answer_text_from_dict(parsed)
        if parsed_text:
            return parsed_text
    return text


# 함수 설명: `_answer_payload()`는 페이로드에서 현재 단계가 사용할 필드만 추출해 표준 구조로 정리합니다.
def _answer_payload(value: Any) -> dict[str, Any]:
    if isinstance(value, dict):
        return deepcopy(value)
    data = getattr(value, "data", None)
    if isinstance(data, dict):
        return deepcopy(data)
    text = _message_text(value).strip()
    return _json_text(text)


# 함수 설명: `_answer_text_from_dict()`는 문자열·원본·DICT에서 현재 단계가 사용할 필드만 추출해 표준 구조로 정리합니다.
def _answer_text_from_dict(value: dict[str, Any]) -> str:
    for key in ("answer_message", "answer", "text", "message", "output"):
        item = value.get(key)
        if isinstance(item, str) and item.strip():
            return item.strip()
    data = value.get("data")
    if isinstance(data, dict):
        return _answer_text_from_dict(data)
    return ""


# 함수 설명: `_message_text()`는 문자열에서 현재 단계가 사용할 필드만 추출해 표준 구조로 정리합니다.
def _message_text(value: Any) -> str:
    for attr in ("text", "content", "message"):
        text = getattr(value, attr, None)
        if isinstance(text, str):
            return text
    data = getattr(value, "data", None)
    if isinstance(data, dict):
        extracted = _answer_text_from_dict(data)
        if extracted:
            return extracted
    return str(value or "")


# 함수 설명: `_json_text()`는 LLM 답변에서 Markdown fence를 제거하고 JSON object 문자열만 추출합니다.
def _json_text(text: str) -> dict[str, Any]:
    if not text:
        return {}
    candidate = text.strip()
    match = re.search(r"```(?:json)?\s*(.*?)\s*```", candidate, re.DOTALL)
    if match:
        candidate = match.group(1).strip()
    elif "{" in candidate and "}" in candidate:
        candidate = candidate[candidate.find("{") : candidate.rfind("}") + 1]
    try:
        parsed = json.loads(candidate)
    except Exception:
        return {}
    return parsed if isinstance(parsed, dict) else {}


# 함수 설명: `_build_answer_sections()`는 답변·응답 section 구성 요소를 모아 다음 단계가 사용할 표준 결과로 만듭니다.
def _build_answer_sections(payload: dict[str, Any], answer_message: str, section_overrides: dict[str, Any] | None = None) -> dict[str, Any]:
    data = _dict(payload.get("data"))
    overrides = _dict(section_overrides)
    result_table_overrides = _dict(overrides.get("result_table"))
    rows = _list(data.get("rows"))
    columns = _string_list(data.get("columns")) or _columns_from_rows(rows)
    display_columns = _string_list(data.get("display_columns")) or _string_list(result_table_overrides.get("display_columns"))
    override_labels = _dict(result_table_overrides.get("column_labels"))
    column_labels = {**override_labels, **_dict(data.get("column_labels"))}
    row_count = _int(data.get("row_count"), len(rows))
    applied_criteria = _applied_criteria(payload)
    evidence = _evidence(payload)
    notices = _notices(payload, row_count, rows)
    downloads = _downloads(payload)
    return {
        "summary": {
            "headline": answer_message,
            "basis": _summary_basis(applied_criteria),
        },
        "result_table": _omit_empty(
            {
                "columns": columns,
                "display_columns": display_columns,
                "column_labels": deepcopy(column_labels),
                "row_source": "data.rows",
                "row_count": row_count,
                "preview_limit": TABLE_PREVIEW_LIMIT,
            }
        ),
        "applied_criteria": applied_criteria,
        "evidence": evidence,
        "notices": notices,
        "downloads": downloads,
        "next_questions": _next_questions(payload),
    }


# 함수 설명: `_applied_criteria()`는 조회 작업과 pandas 계획에서 실제 적용된 날짜·제품·공정·지표 조건을 구성합니다.
def _applied_criteria(payload: dict[str, Any]) -> dict[str, Any]:
    plan = _dict(payload.get("intent_plan"))
    retrieval_jobs = _list(plan.get("retrieval_jobs"))
    pandas_plan = _list(plan.get("pandas_execution_plan"))
    source_results = _list(payload.get("source_results"))
    required_params: dict[str, Any] = {}
    analysis_filters: dict[str, Any] = {}
    retrieval_filters: dict[str, Any] = {}
    datasets: list[dict[str, Any]] = []
    for job in retrieval_jobs:
        if not isinstance(job, dict):
            continue
        alias = str(job.get("source_alias") or job.get("dataset_key") or "").strip()
        dataset_key = str(job.get("dataset_key") or "").strip()
        source_type = str(job.get("source_type") or "").strip()
        if dataset_key or alias:
            datasets.append(_omit_empty({"dataset_key": dataset_key, "source_alias": alias, "source_type": source_type}))
        params = _dict(job.get("required_params"))
        if params:
            required_params[alias or dataset_key or f"job_{len(required_params) + 1}"] = deepcopy(params)
        filters = _dict(job.get("filters"))
        if filters:
            analysis_filters[alias or dataset_key or f"job_{len(analysis_filters) + 1}"] = deepcopy(filters)
    for source in source_results:
        if not isinstance(source, dict):
            continue
        alias = str(source.get("source_alias") or source.get("dataset_key") or "").strip()
        dataset_key = str(source.get("dataset_key") or "").strip()
        source_type = str(source.get("source_type") or "").strip()
        if dataset_key or alias:
            datasets.append(_omit_empty({"dataset_key": dataset_key, "source_alias": alias, "source_type": source_type, "row_count": source.get("row_count")}))
        params = _dict(source.get("applied_params"))
        if params:
            required_params[alias or dataset_key or f"source_{len(required_params) + 1}"] = deepcopy(params)
        pandas_filters = _dict(source.get("pandas_filters")) or _dict(source.get("applied_filters"))
        if pandas_filters:
            analysis_filters[alias or dataset_key or f"source_{len(analysis_filters) + 1}"] = deepcopy(pandas_filters)
        retriever_filters = _dict(_dict(source.get("source_execution")).get("filters_applied_in_retriever"))
        if retriever_filters:
            retrieval_filters[alias or dataset_key or f"source_{len(retrieval_filters) + 1}"] = deepcopy(retriever_filters)
    return _omit_empty(
        {
            "required_params": required_params,
            "analysis_filters": analysis_filters,
            "retrieval_filters": retrieval_filters,
            "group_by": _group_by_columns(pandas_plan),
            "metrics": _metric_columns(payload),
            "datasets": _dedupe_dicts(datasets),
        }
    )


# 함수 설명: `_evidence()`는 조회·pandas 실행 trace에서 답변 수치의 데이터셋과 조건 근거를 구성합니다.
def _evidence(payload: dict[str, Any]) -> dict[str, Any]:
    analysis = _dict(payload.get("analysis"))
    pandas_execution = _dict(_dict(_dict(payload.get("trace")).get("inspection")).get("pandas_execution"))
    step_outputs = _list(analysis.get("step_outputs")) or _list(pandas_execution.get("step_outputs"))
    function_case_results = _list(analysis.get("function_case_results")) or _list(pandas_execution.get("function_case_results"))
    return _omit_empty(
        {
            "datasets": _compact_source_results(_list(payload.get("source_results"))),
            "calculation_rules": deepcopy(_list(payload.get("metadata_refs")))[:10],
            "step_outputs": deepcopy(step_outputs[:6]),
            "function_case_results": deepcopy(function_case_results[:6]),
        }
    )


# 함수 설명: `_notices()`는 warnings와 errors를 사용자에게 보여 줄 중복 없는 안내 목록으로 정리합니다.
def _notices(payload: dict[str, Any], row_count: int, rows: list[Any]) -> list[dict[str, Any]]:
    notices: list[dict[str, Any]] = []
    if row_count == 0 and not rows:
        notices.append({"type": "empty_result", "message": "조건에 맞는 결과 행이 없습니다."})
    for source in _list(payload.get("source_results")):
        if not isinstance(source, dict):
            continue
        execution = _dict(source.get("source_execution"))
        if execution.get("used_dummy_data") is True:
            notices.append({"type": "dummy_data", "message": "현재 결과는 더미 데이터 기준입니다."})
            break
    trace = _dict(payload.get("trace"))
    for item in _list(trace.get("warnings"))[:5]:
        if isinstance(item, dict):
            notices.append({"type": str(item.get("type") or "warning"), "message": str(item.get("message") or item)})
    for item in _list(trace.get("errors"))[:5]:
        if isinstance(item, dict):
            notices.append({"type": str(item.get("type") or "error"), "message": str(item.get("message") or item)})
    return notices


# 함수 설명: `_downloads()`는 저장된 data_ref에서 최종 답변에 제공할 다운로드 항목을 구성합니다.
def _downloads(payload: dict[str, Any]) -> list[dict[str, Any]]:
    refs = []
    for ref in _list(payload.get("data_refs")):
        if isinstance(ref, dict):
            refs.append(deepcopy(ref))
    data_ref = _dict(_dict(payload.get("data")).get("data_ref"))
    if data_ref:
        refs.append(deepcopy(data_ref))
    return _dedupe_dicts(refs)


# 함수 설명: `_summary_basis()`는 답변 요약이 어떤 rows·지표·조건을 기준으로 작성됐는지 근거를 구성합니다.
def _summary_basis(applied_criteria: dict[str, Any]) -> list[str]:
    basis = []
    if applied_criteria.get("required_params"):
        basis.append("조회 필수 조건을 적용했습니다.")
    if applied_criteria.get("analysis_filters"):
        basis.append("공정/제품/상태 조건은 분석 단계에서 적용했습니다.")
    if applied_criteria.get("metrics"):
        basis.append("요청 지표를 기준으로 집계했습니다.")
    return basis


# 함수 설명: `_next_questions()`는 questions 관련 정보를 계산·선별해 후속 분석 또는 표시 단계에 전달합니다.
def _next_questions(payload: dict[str, Any]) -> list[str]:
    data = _dict(payload.get("data"))
    row_count = _int(data.get("row_count"), len(_list(data.get("rows"))))
    if row_count <= 0:
        return ["조건을 넓혀서 다시 조회할까요?"]
    return ["이 결과를 제품별 또는 공정별로 더 나눠볼까요?", "원본 데이터를 내려받아 상세 Lot/Device를 확인할까요?"]


# 함수 설명: `_compact_source_results()`는 데이터 소스·결과에서 후속 단계에 필요한 정보만 남겨 payload와 token 크기를 줄입니다.
def _compact_source_results(source_results: list[Any]) -> list[dict[str, Any]]:
    compact = []
    for source in source_results:
        if not isinstance(source, dict):
            continue
        compact.append(
            _omit_empty(
                {
                    "dataset_key": source.get("dataset_key"),
                    "source_alias": source.get("source_alias"),
                    "source_type": source.get("source_type"),
                    "status": source.get("status"),
                    "row_count": source.get("row_count"),
                    "applied_params": source.get("applied_params"),
                    "pandas_filters": source.get("pandas_filters") or source.get("applied_filters"),
                }
            )
        )
    return compact


# 함수 설명: `_build_next_turn_state()`는 다음 단계·TURN·상태 구성 요소를 모아 다음 단계가 사용할 표준 결과로 만듭니다.
def _build_next_turn_state(payload: dict[str, Any]) -> dict[str, Any]:
    # 이전 state 전체를 다시 복사하지 않고 현재 turn에서 확정된 정보만 새 상태로 만듭니다.
    # 이 방식으로 이전 retrieval job·source ref·download ref가 새 질문 뒤에도 남는 것을 차단합니다.
    previous_state = _dict(payload.get("state"))
    request = _dict(payload.get("request"))
    state: dict[str, Any] = {}
    session_id = str(request.get("session_id") or previous_state.get("session_id") or "").strip()
    if session_id:
        state["session_id"] = session_id
    state["last_question"] = _dict(payload.get("request")).get("question", "")
    state["last_answer_message"] = _clip_text(payload.get("answer_message"), 1000)
    state["current_data"] = _current_data_state(payload)
    followup_sources = _followup_source_results(payload)
    if followup_sources:
        state["followup_source_results"] = followup_sources
    runtime_source_refs = _runtime_source_refs(payload)
    if runtime_source_refs:
        state["runtime_source_refs"] = runtime_source_refs
    if request:
        # 하위 호환을 위한 전체 request 복사 대신 후속 판정에 필요한 현재 질문만 last_question에 유지합니다.
        state["last_question"] = request.get("question", state.get("last_question", ""))
    intent_plan = _compact_intent_plan(_dict(payload.get("intent_plan")))
    if intent_plan:
        state["last_intent_plan"] = intent_plan
    applied_criteria = _applied_criteria(payload)
    if applied_criteria:
        state["last_applied_criteria"] = applied_criteria
    return _omit_empty(state)


# 함수 설명: `_current_data_state()`는 현재 결과의 rows·columns·row_count·data_ref를 다음 질문용 작은 상태로 만듭니다.
def _current_data_state(payload: dict[str, Any]) -> dict[str, Any]:
    data = _dict(payload.get("data"))
    rows = _list(data.get("rows"))
    columns = _string_list(data.get("columns")) or _columns_from_rows(rows)
    return _omit_empty(
        {
            "row_count": _int(data.get("row_count"), len(rows)),
            "columns": columns,
            "result_columns": columns,
            "preview_rows": deepcopy(rows[:5]),
            "data_ref": deepcopy(data.get("data_ref")),
            "source_aliases": _source_aliases(payload),
            "source_dataset_keys": _source_dataset_keys(payload),
            "source_columns_by_alias": _source_columns_by_alias(payload),
        }
    )


# 함수 설명: `_followup_source_results()`는 후속 질문이 재사용할 source result를 preview와 참조 중심으로 압축합니다.
def _followup_source_results(payload: dict[str, Any]) -> list[dict[str, Any]]:
    runtime_sources = _dict(payload.get("runtime_sources"))
    result = []
    for source in _list(payload.get("source_results")):
        if not isinstance(source, dict):
            continue
        alias = str(source.get("source_alias") or source.get("dataset_key") or "").strip()
        rows = _list(runtime_sources.get(alias))
        result.append(
            _omit_empty(
                {
                    "source_alias": alias,
                    "dataset_key": source.get("dataset_key"),
                    "source_type": source.get("source_type"),
                    "row_count": source.get("row_count") if source.get("row_count") is not None else len(rows),
                    "columns": _string_list(source.get("columns")) or _columns_from_rows(rows),
                    "preview_rows": deepcopy(rows[:5]),
                    "data_ref": deepcopy(source.get("data_ref")),
                    "applied_params": deepcopy(source.get("applied_params")),
                    "applied_filters": deepcopy(source.get("applied_filters") or source.get("pandas_filters")),
                }
            )
        )
    return [item for item in result if item]


# 함수 설명: `_runtime_source_refs()`는 메모리의 runtime source를 직접 저장하지 않고 재조회 가능한 source 참조만 구성합니다.
def _runtime_source_refs(payload: dict[str, Any]) -> dict[str, dict[str, Any]]:
    refs: dict[str, dict[str, Any]] = {}
    for ref in _list(payload.get("data_refs")):
        if not isinstance(ref, dict):
            continue
        if str(ref.get("role") or "") != "source_rows":
            continue
        alias = str(ref.get("source_alias") or "").strip()
        if alias:
            refs[alias] = deepcopy(ref)
    return refs


# 함수 설명: `_source_aliases()`는 aliases 정보를 현재 질문과 응답 계약에 맞는 dict 또는 행으로 구성합니다.
def _source_aliases(payload: dict[str, Any]) -> list[str]:
    aliases = []
    for source in _list(payload.get("source_results")):
        if isinstance(source, dict):
            alias = str(source.get("source_alias") or source.get("dataset_key") or "").strip()
            if alias and alias not in aliases:
                aliases.append(alias)
    for alias in _dict(payload.get("runtime_sources")):
        text = str(alias or "").strip()
        if text and text not in aliases:
            aliases.append(text)
    return aliases


# 함수 설명: `_source_dataset_keys()`는 데이터셋·key 정보를 현재 질문과 응답 계약에 맞는 dict 또는 행으로 구성합니다.
def _source_dataset_keys(payload: dict[str, Any]) -> list[str]:
    keys = []
    for source in _list(payload.get("source_results")):
        if isinstance(source, dict):
            key = str(source.get("dataset_key") or "").strip()
            if key and key not in keys:
                keys.append(key)
    return keys


# 함수 설명: `_source_columns_by_alias()`는 컬럼·BY·alias 정보를 현재 질문과 응답 계약에 맞는 dict 또는 행으로 구성합니다.
def _source_columns_by_alias(payload: dict[str, Any]) -> dict[str, list[str]]:
    runtime_sources = _dict(payload.get("runtime_sources"))
    result: dict[str, list[str]] = {}
    for source in _list(payload.get("source_results")):
        if not isinstance(source, dict):
            continue
        alias = str(source.get("source_alias") or source.get("dataset_key") or "").strip()
        if not alias:
            continue
        columns = _string_list(source.get("columns")) or _columns_from_rows(_list(runtime_sources.get(alias)))
        if columns:
            result[alias] = columns
    for alias, rows in runtime_sources.items():
        text = str(alias or "").strip()
        if text and text not in result:
            columns = _columns_from_rows(_list(rows))
            if columns:
                result[text] = columns
    return result


# 함수 설명: `_compact_intent_plan()`는 의도 계획·PLAN에서 후속 단계에 필요한 정보만 남겨 payload와 token 크기를 줄입니다.
def _compact_intent_plan(plan: dict[str, Any]) -> dict[str, Any]:
    return _omit_empty(
        {
            "analysis_kind": plan.get("analysis_kind"),
            "request_scope": plan.get("request_scope"),
            "reuse_strategy": plan.get("reuse_strategy"),
            "condition_resolution": deepcopy(_dict(plan.get("condition_resolution"))),
            "retrieval_jobs": _compact_retrieval_jobs(_list(plan.get("retrieval_jobs"))),
            "pandas_execution_plan": deepcopy(_list(plan.get("pandas_execution_plan"))[:8]),
            "pandas_function_cases": deepcopy(_list(plan.get("pandas_function_cases"))[:5]),
            "output_contract": deepcopy(_dict(plan.get("output_contract"))),
        }
    )


# 함수 설명: `_compact_retrieval_jobs()`는 데이터 조회·조회 작업에서 후속 단계에 필요한 정보만 남겨 payload와 token 크기를 줄입니다.
def _compact_retrieval_jobs(jobs: list[Any]) -> list[dict[str, Any]]:
    compact = []
    for job in jobs:
        if not isinstance(job, dict):
            continue
        compact.append(
            _omit_empty(
                {
                    "dataset_key": job.get("dataset_key"),
                    "source_alias": job.get("source_alias"),
                    "source_type": job.get("source_type"),
                    "required_params": deepcopy(job.get("required_params")),
                    "filters": deepcopy(job.get("filters")),
                }
            )
        )
    return compact


# 함수 설명: `_group_by_columns()`는 의도 계획의 pandas 단계에서 실제 그룹 기준 컬럼을 추출합니다.
def _group_by_columns(pandas_plan: list[Any]) -> list[str]:
    columns: list[str] = []
    for step in pandas_plan:
        if not isinstance(step, dict):
            continue
        for key in ("groupby_columns", "group_by", "group_by_columns", "group_columns"):
            value = step.get(key)
            if isinstance(value, list):
                for item in value:
                    text = str(item or "").strip()
                    if text and text not in columns:
                        columns.append(text)
            elif isinstance(value, str) and value.strip() and value.strip() not in columns:
                columns.append(value.strip())
    return columns


# 함수 설명: `_metric_columns()`는 결과 컬럼 중 수량·실적·비율처럼 답변 지표로 사용할 컬럼을 선별합니다.
def _metric_columns(payload: dict[str, Any]) -> list[str]:
    data = _dict(payload.get("data"))
    columns = _string_list(data.get("columns")) or _columns_from_rows(_list(data.get("rows")))
    rows = _list(data.get("rows"))
    return [column for column in columns if _column_has_numeric_value(rows, column)]


# 함수 설명: `_column_has_numeric_value()`는 HAS·numeric·값 관련 정보를 계산·선별해 후속 분석 또는 표시 단계에 전달합니다.
def _column_has_numeric_value(rows: list[Any], column: str) -> bool:
    for row in rows:
        if not isinstance(row, dict):
            continue
        value = row.get(column)
        if value is None or isinstance(value, bool) or isinstance(value, str):
            continue
        try:
            number = float(value)
        except Exception:
            continue
        if number != number:
            continue
        return True
    return False


# 함수 설명: `_display_row()`는 행을 Markdown 또는 사용자 화면에서 안전하게 읽을 수 있는 표현으로 변환합니다.
def _display_row(row: dict[str, Any], columns: list[str]) -> dict[str, Any]:
    if not columns:
        columns = [str(key) for key in row]
    return {column: _display_value(row.get(column, "")) for column in columns}


# 함수 설명: `_display_value()`는 None·숫자·복합 값을 사용자에게 읽기 좋은 짧은 문자열로 표시합니다.
def _display_value(value: Any) -> Any:
    formatted = _format_number(value)
    if formatted is not None:
        return formatted
    if isinstance(value, (dict, list)):
        return deepcopy(value)
    return value


# 함수 설명: `_format_number()`는 number을 Markdown 또는 사용자 화면에서 안전하게 읽을 수 있는 표현으로 변환합니다.
def _format_number(value: Any) -> str | None:
    if value is None or isinstance(value, bool) or isinstance(value, str):
        return None
    try:
        number = float(value)
    except Exception:
        return None
    if number != number:
        return None
    if abs(number) >= 10000:
        k_value = number / 1000
        return f"{int(k_value):,}K" if float(k_value).is_integer() else f"{k_value:,.1f}K"
    return f"{int(number):,}" if float(number).is_integer() else f"{number:,.1f}"


# 함수 설명: `_columns_from_rows()`는 행 목록의 key 등장 순서를 유지하면서 결과 테이블의 컬럼 목록을 계산합니다.
def _columns_from_rows(rows: list[Any]) -> list[str]:
    columns: list[str] = []
    for row in rows:
        if not isinstance(row, dict):
            continue
        for key in row:
            text = str(key)
            if text not in columns:
                columns.append(text)
    return columns


# 함수 설명: `_string_list()`는 여러 형태의 입력에서 비어 있지 않은 문자열만 뽑아 중복 없는 목록으로 정리합니다.
def _string_list(value: Any) -> list[str]:
    return [str(item) for item in value if str(item or "").strip()] if isinstance(value, list) else []


# 함수 설명: `_list()`는 입력값을 list로 정규화하고 목록이 아닌 값은 안전한 기본 목록으로 바꿉니다.
def _list(value: Any) -> list[Any]:
    return value if isinstance(value, list) else []


# 함수 설명: `_dict()`는 입력값이 dict인지 확인하고 아니면 빈 dict를 반환해 후속 key 접근 오류를 막습니다.
def _dict(value: Any) -> dict[str, Any]:
    return value if isinstance(value, dict) else {}


# 함수 설명: `_int()`는 문자열이나 숫자 입력을 정수로 변환하고 실패하면 안전한 기본값을 사용합니다.
def _int(value: Any, default: int = 0) -> int:
    try:
        return int(value)
    except Exception:
        return default


# 함수 설명: `_clip_text()`는 문자열을 허용 길이 안으로 자르되 비어 있는 값과 말줄임 표시를 일관되게 처리합니다.
def _clip_text(value: Any, limit: int) -> str:
    text = str(value or "").strip()
    return text[:limit] if len(text) > limit else text


# 함수 설명: `_omit_empty()`는 dict에서 빈 문자열·빈 목록·None 항목을 제거해 전달 payload를 작게 유지합니다.
def _omit_empty(value: dict[str, Any]) -> dict[str, Any]:
    return {key: item for key, item in value.items() if item not in (None, "", [], {})}


# 함수 설명: `_dedupe_dicts()`는 dicts의 중복을 제거하고 최초 등장 순서를 유지합니다.
def _dedupe_dicts(items: list[dict[str, Any]]) -> list[dict[str, Any]]:
    seen: set[str] = set()
    result: list[dict[str, Any]] = []
    for item in items:
        signature = json.dumps(item, ensure_ascii=False, sort_keys=True, default=str)
        if signature in seen:
            continue
        seen.add(signature)
        result.append(item)
    return result


# Langflow 컴포넌트 클래스: inputs/outputs가 캔버스 포트와 JSON edge 계약을 정의합니다.
# 실제 업무 규칙은 위의 주요 함수에 두어 UI 실행과 단위 테스트가 같은 로직을 사용합니다.
class AnswerResponseBuilder(Component):
    display_name = "20 답변 응답 생성기"
    description = "Langflow 에이전트/LLM 답변 문장과 결정된 데이터를 합쳐 페이로드를 완성합니다."
    inputs = [DataInput(name="payload", display_name="페이로드", required=True), MessageTextInput(name="answer_text", display_name="답변 문장", required=False)]
    outputs = [Output(name="payload_out", display_name="페이로드 출력", method="build_payload")]

    # Langflow 출력 함수: '페이로드 출력 (payload_out)' 포트가 요청될 때 실행됩니다.
    # 핵심 처리 결과를 Langflow Data/Message 형식으로 감싸 다음 노드에 전달합니다.
    def build_payload(self) -> Data:
        return Data(data=build_answer_response(getattr(self, "payload", None), getattr(self, "answer_text", "")))

