# =============================================================================
# 컴포넌트 개요: GaiA Output Adapter
# 역할: 최종 답변과 참고자료를 GaiA 응답 계약으로 정규화해 표준 Chat Output으로 전달합니다.
# 주요 입력: 답변 Message/Data/DataFrame, 문서·URL·이미지·노하우·후속 질문 참조
# 주요 출력: Langflow Message, 구조화된 GaiA Response Data
# 유지보수 포인트: 어댑터는 메시지를 저장하지 않고 표준 Chat Output이 한 번만 저장합니다.
# =============================================================================

import json
import logging
from typing import Any

import orjson
from fastapi.encoders import jsonable_encoder

from lfx.base.io.chat import ChatComponent
from lfx.helpers.data import safe_convert
from lfx.inputs.inputs import HandleInput
from lfx.schema.data import Data
from lfx.schema.dataframe import DataFrame
from lfx.schema.message import Message
from lfx.template.field.base import Output
from lfx.utils.constants import MESSAGE_SENDER_AI

logger = logging.getLogger(__name__)

REFERENCE_TYPES = {
    "docs": "doc",
    "images": "image",
    "knowhows": "knowhow",
    "followup_questions": "followup_question",
    "urls": "url",
}
REFERENCE_KEYS = tuple(REFERENCE_TYPES.keys())
OUTPUT_METADATA_KEYS = (*REFERENCE_KEYS, "trace_id", "usage")

REFERENCE_ALLOWED_FIELDS = {
    "docs": {
        "type",
        "srcType",
        "name",
        "docId",
        "extension",
        "path",
        "url",
        "page",
        "totalPage",
        "startPage",
        "chunkId",
        "score",
        "quote",
        "sectionTitle",
    },
    "urls": {"type", "id", "name", "title", "url", "snippet", "publishedAt", "source", "rank"},
    "images": {"type", "id", "value"},
    "knowhows": {
        "type",
        "id",
        "knowhow_id",
        "knowhow_no",
        "knowhow",
        "tab_name",
        "tab_id",
        "user_id",
        "user_name",
        "user_department",
    },
    "followup_questions": {"type", "id", "value"},
}
REFERENCE_REQUIRED_FIELDS = {
    "docs": ("srcType", "name", "docId", "startPage"),
    "urls": (),
    "images": ("id", "value"),
    "knowhows": ("id", "knowhow_id", "knowhow"),
    "followup_questions": ("value",),
}
REFERENCE_NUMBER_FIELDS = {
    "docs": {"page", "totalPage", "startPage"},
    "urls": {"rank"},
    "images": set(),
    "knowhows": {"knowhow_no"},
    "followup_questions": set(),
}


# Langflow 컴포넌트 클래스: 최종 답변과 참고자료를 GaiA answer/metadata에 담아 표준 Chat Output으로 전달하는 어댑터입니다.
class GaiAOutputAdapter(ChatComponent):
    display_name = "GaiA Output Adapter"
    description = (
        "최종 답변과 참고자료를 GaiA AgentBuilder가 이해하는 answer/metadata 형식으로 정리합니다. "
        "변환된 Message는 뒤의 표준 Chat Output이 Playground와 실행 API에 출력합니다."
    )
    documentation: str = "https://docs.langflow.org/chat-input-and-output"
    icon = "MessagesSquare"
    name = "GaiAOutputAdapter"
    minimized = True

    inputs = [
        HandleInput(
            name="input_value",
            display_name="answer",
            input_types=["Data", "DataFrame", "Message"],
            required=True,
        ),
        HandleInput(name="docs", display_name="docs", input_types=["Data", "DataFrame"], required=False),
        HandleInput(name="urls", display_name="urls", input_types=["Data", "DataFrame"], required=False),
        HandleInput(name="images", display_name="images", input_types=["Data", "DataFrame"], required=False),
        HandleInput(
            name="knowhows",
            display_name="knowhows",
            input_types=["Data", "DataFrame"],
            required=False,
        ),
        HandleInput(
            name="followup_questions",
            display_name="followup_questions",
            input_types=["Data", "DataFrame"],
            required=False,
        ),
    ]

    outputs = [
        Output(
            display_name="message",
            name="message",
            method="message_response",
            types=["Message"],
            group_outputs=True,
        ),
        Output(
            display_name="GaiA Response",
            name="gaia_response",
            method="gaia_response_output",
            types=["Data"],
            group_outputs=True,
        ),
    ]

    # 함수 설명: None, NaN, 빈 문자열과 빈 컬렉션을 공통 빈 값으로 판정합니다.
    def _is_empty(self, value: Any) -> bool:
        if value is None:
            return True
        try:
            if value != value:
                return True
        except Exception:
            pass
        if isinstance(value, str):
            return not value.strip()
        if isinstance(value, (list, tuple, set, dict)):
            return len(value) == 0
        return False

    # 함수 설명: Langflow Data·DataFrame·Message와 JSON 문자열을 일반 Python 값으로 변환합니다.
    def _plain_value(self, value: Any) -> Any:
        if self._is_empty(value):
            return {}
        if isinstance(value, Data):
            return jsonable_encoder(value.data)
        if isinstance(value, DataFrame):
            try:
                return [jsonable_encoder(row.to_dict()) for _, row in value.iterrows()]
            except Exception:
                return jsonable_encoder(value)
        if isinstance(value, Message):
            data = getattr(value, "data", None) or getattr(value, "a2a_data", None)
            if not self._is_empty(data):
                return jsonable_encoder(data)
            text = getattr(value, "text", "")
            return {"text": text} if text else {}
        if isinstance(value, str):
            stripped = value.strip()
            if not stripped:
                return {}
            try:
                return jsonable_encoder(orjson.loads(stripped))
            except Exception:
                return stripped
        return jsonable_encoder(value)

    # 함수 설명: 입력 값을 구조화된 dict로 변환하며 그 외 형식은 빈 dict로 처리합니다.
    def _as_dict(self, value: Any) -> dict:
        plain_value = self._plain_value(value)
        return plain_value if isinstance(plain_value, dict) else {}

    # 함수 설명: 최종 답변 본문을 Message/Data/일반 값에서 일관된 문자열로 꺼냅니다.
    def _text_value(self, value: Any) -> str:
        if isinstance(value, Message):
            return str(getattr(value, "text", "") or "")
        if isinstance(value, Data):
            data = getattr(value, "data", None)
            if isinstance(data, dict) and data.get("text") not in (None, ""):
                return str(data.get("text"))
        return safe_convert(value)

    # 함수 설명: DataFrame의 열 중심 dict를 행 목록으로 바꿀 때 숫자 인덱스를 우선 정렬합니다.
    def _index_sort_key(self, key: Any):
        text = str(key)
        return (0, int(text)) if text.isdigit() else (1, text)

    # 함수 설명: 동일 길이의 열 중심 dict를 GaiA 참조자료 행 목록으로 변환합니다.
    def _records_from_column_dict(self, value: Any):
        if not isinstance(value, dict) or not value:
            return None
        columns = {}
        lengths = set()
        for key, column in value.items():
            if isinstance(column, dict):
                ordered = [column[item] for item in sorted(column.keys(), key=self._index_sort_key)]
            elif isinstance(column, list):
                ordered = column
            else:
                return None
            columns[str(key)] = ordered
            lengths.add(len(ordered))
        if len(lengths) != 1:
            return None
        count = lengths.pop()
        return [{key: columns[key][index] for key in columns} for index in range(count)]

    # 함수 설명: docs={docs:[...]}처럼 한 번 더 감싼 참조자료 값을 풀어냅니다.
    def _unwrap_reference_collection(self, field_name: str, value: Any) -> Any:
        if isinstance(value, dict) and field_name in value:
            return value.get(field_name)
        return value

    # 함수 설명: 필수 문자열 필드를 공백 제거한 값으로 정규화합니다.
    def _string_value(self, value: Any) -> str:
        if self._is_empty(value):
            return ""
        return str(value).strip()

    # 함수 설명: 페이지와 순번 필드를 정수로 변환하며 변환 불가 값은 None으로 반환합니다.
    def _integer_value(self, value: Any) -> int | None:
        if self._is_empty(value):
            return None
        try:
            return int(float(str(value).strip()))
        except Exception:
            return None

    # 함수 설명: 검색 실패를 나타내는 placeholder 참조자료는 최종 응답에서 제외합니다.
    def _is_placeholder_reference(self, item: Any) -> bool:
        return isinstance(item, dict) and str(item.get("status") or "").strip().lower() in {
            "not_found",
            "no_result",
            "empty",
        }

    # 함수 설명: 참조자료의 숫자와 문자열 필드를 GaiA 계약 타입으로 맞춥니다.
    def _coerce_reference_value(self, field_name: str, key: str, value: Any) -> Any:
        if key in REFERENCE_NUMBER_FIELDS[field_name]:
            number = self._integer_value(value)
            return number if number is not None else value
        if isinstance(value, str):
            return value.strip()
        return value

    # 함수 설명: 참조자료 한 건의 허용 필드, type, 필수 값을 검증하고 정규화합니다.
    def _validate_reference_item(self, field_name: str, item: dict) -> dict:
        allowed = REFERENCE_ALLOWED_FIELDS[field_name]
        canonical_type = REFERENCE_TYPES[field_name]
        unknown_keys = sorted(
            str(key) for key in item if str(key) not in allowed and not self._is_empty(item.get(key))
        )
        if unknown_keys:
            raise ValueError(f"{field_name} reference item has unsupported field(s): {', '.join(unknown_keys)}")
        item_type = item.get("type")
        if not self._is_empty(item_type) and self._string_value(item_type) != canonical_type:
            raise ValueError(f"{field_name} reference item requires type={canonical_type!r}")
        normalized = {}
        for key in allowed:
            if key in item and not self._is_empty(item.get(key)):
                normalized[key] = self._coerce_reference_value(field_name, key, item.get(key))
        for required_key in REFERENCE_REQUIRED_FIELDS[field_name]:
            if self._is_empty(normalized.get(required_key)):
                raise ValueError(f"{field_name} reference item requires a non-empty {required_key}")
        if field_name == "docs" and self._string_value(normalized.get("srcType")) != "upload":
            raise ValueError('docs reference item requires srcType="upload"')
        if field_name == "knowhows" and self._string_value(normalized.get("id")) != self._string_value(
            normalized.get("knowhow_id")
        ):
            raise ValueError("knowhows reference item requires id and knowhow_id to match")
        return normalized

    # 함수 설명: 참조자료 한 건을 일반 dict로 변환한 뒤 필드 계약을 검증합니다.
    def _normalize_reference_item(self, field_name: str, item: Any) -> dict:
        plain_item = self._plain_value(item)
        if not isinstance(plain_item, dict):
            raise ValueError(f"{field_name} reference item must be an object")
        return self._validate_reference_item(field_name, plain_item)

    # 함수 설명: 여러 입력 표현을 GaiA 참조자료 객체 목록으로 통일합니다.
    def _normalize_reference_collection(self, field_name: str, value: Any) -> list[dict]:
        plain_value = self._unwrap_reference_collection(field_name, self._plain_value(value))
        if self._is_empty(plain_value):
            return []
        records = self._records_from_column_dict(plain_value)
        if records is not None:
            items = records
        elif isinstance(plain_value, (list, tuple)):
            items = plain_value
        else:
            items = [plain_value]
        normalized = []
        for item in items:
            if self._is_empty(item) or self._is_placeholder_reference(item):
                continue
            normalized.append(self._normalize_reference_item(field_name, item))
        return normalized

    # 함수 설명: 개별 입력 포트의 참조자료 중 실제 값이 있는 항목만 응답 payload에 구성합니다.
    def _reference_payload_from_ports(self) -> dict:
        payload: dict = {}
        for field_name in REFERENCE_KEYS:
            references = self._normalize_reference_collection(field_name, getattr(self, field_name, None))
            if references:
                payload[field_name] = references
        return payload

    # 함수 설명: 앞 단계 Message.data의 nested metadata 또는 top-level canonical key에서 참조자료를 읽습니다.
    def _reference_payload_from_answer_data(self, answer_data: dict[str, Any]) -> dict:
        metadata = answer_data.get("metadata") if isinstance(answer_data.get("metadata"), dict) else {}
        payload: dict[str, list[dict[str, Any]]] = {}
        for field_name in REFERENCE_KEYS:
            value = metadata.get(field_name) if field_name in metadata else answer_data.get(field_name)
            references = self._normalize_reference_collection(field_name, value)
            if references:
                payload[field_name] = references
        return payload

    # 함수 설명: Message와 개별 포트에서 들어온 참조자료를 순서대로 합치고 동일 항목을 한 번만 유지합니다.
    def _merge_reference_payloads(self, *payloads: dict[str, Any]) -> dict:
        merged: dict[str, list[dict[str, Any]]] = {}
        for field_name in REFERENCE_KEYS:
            items: list[dict[str, Any]] = []
            seen: set[str] = set()
            for payload in payloads:
                for item in payload.get(field_name, []) if isinstance(payload, dict) else []:
                    marker = json.dumps(item, ensure_ascii=False, sort_keys=True, default=str)
                    if marker in seen:
                        continue
                    seen.add(marker)
                    items.append(item)
            if items:
                merged[field_name] = items
        return merged

    # 함수 설명: 토큰 사용량 값을 오류 없이 정수로 변환합니다.
    def _int_token(self, value: Any) -> int:
        try:
            return int(value or 0)
        except Exception:
            return 0

    # 함수 설명: 모델 사용량 한 건을 prompt/completion/total 토큰 계약으로 정규화합니다.
    def _normalize_usage_item(self, value: Any) -> dict:
        safe_value = self._plain_value(value)
        if not isinstance(safe_value, dict):
            return {}
        prompt_tokens = self._int_token(safe_value.get("prompt_tokens"))
        completion_tokens = self._int_token(safe_value.get("completion_tokens"))
        total_tokens = self._int_token(safe_value.get("total_tokens")) or prompt_tokens + completion_tokens
        if not (prompt_tokens or completion_tokens or total_tokens):
            return {}
        normalized = {
            "prompt_tokens": prompt_tokens,
            "completion_tokens": completion_tokens,
            "total_tokens": total_tokens,
        }
        if safe_value.get("model"):
            normalized["model"] = str(safe_value.get("model"))
        return normalized

    # 함수 설명: 중첩된 usage 입력을 펼치고 중복 항목을 제거합니다.
    def _normalize_usage_list(self, *values: Any) -> list[dict]:
        usage_items = []
        seen = set()
        stack = list(values)
        while stack:
            value = self._plain_value(stack.pop(0))
            if self._is_empty(value):
                continue
            if isinstance(value, list):
                stack[0:0] = value
                continue
            item = self._normalize_usage_item(value)
            if item:
                marker = str(sorted(item.items()))
                if marker not in seen:
                    seen.add(marker)
                    usage_items.append(item)
        return usage_items

    # 함수 설명: 누락된 참조자료도 빈 배열로 포함하는 고정 GaiA metadata envelope를 만듭니다.
    def _response_metadata(self, port_references: dict, usage_items: list[dict], trace_id: Any = "") -> dict:
        return {
            "docs": port_references.get("docs", []),
            "images": port_references.get("images", []),
            "knowhows": port_references.get("knowhows", []),
            "followup_questions": port_references.get("followup_questions", []),
            "urls": port_references.get("urls", []),
            "trace_id": str(trace_id or ""),
            "usage": usage_items,
        }

    # 함수 설명: 상태 payload를 한글이 보존되는 JSON 로그 문자열로 안전하게 변환합니다.
    def _json_for_log(self, value: Any) -> str:
        try:
            return json.dumps(value, ensure_ascii=False, default=str)
        except Exception:
            return str(value)

    # 함수 설명: 답변 본문과 참조자료 및 사용량을 최종 GaiA 응답 계약으로 조립합니다.
    def _build_response_payload(self) -> dict:
        input_value = getattr(self, "input_value", "")
        text = self._text_value(input_value)
        answer_data = self._as_dict(input_value)
        answer_metadata = answer_data.get("metadata") if isinstance(answer_data.get("metadata"), dict) else {}
        port_references = self._merge_reference_payloads(
            self._reference_payload_from_answer_data(answer_data),
            self._reference_payload_from_ports(),
        )
        output_metadata = self._response_metadata(
            port_references,
            self._normalize_usage_list(answer_metadata.get("usage"), answer_data.get("usage")),
            answer_metadata.get("trace_id") or answer_data.get("trace_id"),
        )
        return {"answer": text, "metadata": output_metadata}

    # 함수 설명: 운영 로그에는 원문 대신 답변 길이와 참조자료 개수 등 안전한 요약만 남깁니다.
    def _status_from_payload(self, payload: dict) -> dict:
        metadata_payload = payload.get("metadata") or {}
        return {
            "component": "GaiA Output Adapter",
            "answer_length": len(str(payload.get("answer") or "")),
            "metadata_keys": sorted(str(key) for key in metadata_payload.keys()),
            "reference_counts": {
                str(key): len(value)
                for key, value in metadata_payload.items()
                if key in REFERENCE_KEYS and isinstance(value, list)
            },
            "usage_count": len(metadata_payload.get("usage") or []),
        }

    # 함수 설명: 최종 응답의 안전한 상태 요약을 서버 로그와 컴포넌트 상태에 기록합니다.
    def _log_payload(self, payload: dict) -> None:
        debug_text = self._json_for_log(self._status_from_payload(payload))
        logger.warning("GAIA_DEBUG GaiA Output payload=%s", debug_text)
        print(f"GAIA_DEBUG GaiA Output payload={debug_text}", flush=True)

    # 주요 메서드: GaiA payload를 Message에 담되 저장은 뒤의 표준 Chat Output에 위임합니다.
    async def message_response(self) -> Message:
        payload = self._build_response_payload()
        input_value = getattr(self, "input_value", None)
        message = input_value if isinstance(input_value, Message) else Message(text=payload["answer"])
        message.text = payload["answer"]
        message.sender = MESSAGE_SENDER_AI
        message.sender_name = "AI"
        if not getattr(message, "session_id", ""):
            message.session_id = getattr(getattr(self, "graph", None), "session_id", "") or ""
        if not isinstance(getattr(message, "data", None), dict):
            message.data = {}
        message.data["gaia_response"] = payload
        message.metadata = payload["metadata"]
        self.status = message
        return message

    # 주요 메서드: HTTP/Tool 호출이 중간 Message 저장 없이 사용할 구조화된 GaiA Response Data를 반환합니다.
    async def gaia_response_output(self) -> Data:
        payload = self._build_response_payload()
        self._log_payload(payload)
        result = Data(data=payload)
        self.status = result
        return result

# -*- coding: utf-8 -*-
# =============================================================================
# 컴포넌트 개요: 05A 상위 결과 파라미터 바인더
# 역할: Workflow Orchestrator가 전달한 상위 분석 결과의 식별자를 신뢰 카탈로그 규칙에 따라 다음 조회 작업의 필수 파라미터로 연결합니다.
# 주요 입력: 상위 결과와 신뢰 조회 작업이 포함된 페이로드 (payload) · 필수
# 주요 출력: 파라미터가 연결된 페이로드 (payload_out)
# 처리 흐름: upstream_result 전체 행을 읽고 source_config.upstream_bindings를 검증한 뒤 required_params에 식별자 값을 주입합니다.
# 유지보수 포인트: LLM이 만든 binding은 사용하지 않으며 누락·중복·상한 초과 시 조회 작업을 실행 불가능 상태로 바꾸는 fail-closed 정책을 유지합니다.
# =============================================================================

from __future__ import annotations

import json
from copy import deepcopy
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, Output
from lfx.schema.data import Data

UPSTREAM_SOURCE_ALIAS = "upstream_result"
DEFAULT_MAX_VALUES = 200
MAX_ALLOWED_VALUES = 10_000
SUPPORTED_OPERATORS = {"in", "eq"}
BLOCKED_SOURCE_TYPE = "upstream_binding_blocked"


# 주요 함수: 명시적 orchestration 요청에서만 상위 결과 식별자를 다음 retrieval job의 required_params로 연결합니다.
def bind_upstream_entity_parameters(payload_value: Any) -> dict[str, Any]:
    payload = _payload(payload_value)
    orchestration = payload.get("orchestration") if isinstance(payload.get("orchestration"), dict) else {}
    upstream_ref = _ref_id(orchestration.get("upstream_result_ref"))
    if not upstream_ref:
        # 기존 단일/후속 분석에서는 payload와 trace를 전혀 바꾸지 않습니다.
        return payload

    plan = payload.get("intent_plan") if isinstance(payload.get("intent_plan"), dict) else {}
    jobs = [item for item in plan.get("retrieval_jobs", []) if isinstance(item, dict)] if isinstance(plan.get("retrieval_jobs"), list) else []
    if not jobs:
        _record_inspection(payload, "skipped", [], [], reason="no_retrieval_jobs")
        return payload

    runtime_sources = payload.get("runtime_sources") if isinstance(payload.get("runtime_sources"), dict) else {}
    upstream_rows = runtime_sources.get(UPSTREAM_SOURCE_ALIAS)
    errors: list[dict[str, Any]] = []
    summaries: list[dict[str, Any]] = []
    bound_jobs: list[dict[str, Any]] = []

    if str(orchestration.get("status") or "").lower() != "ok" or not isinstance(upstream_rows, list) or not upstream_rows:
        errors.append(
            _issue(
                "upstream_result_unavailable",
                "MongoDB에서 완전한 상위 결과를 복원하지 못해 후속 데이터 조회를 차단했습니다.",
            )
        )
    else:
        for index, job in enumerate(jobs):
            bound_job, job_summaries, job_errors = _bind_job(job, upstream_rows, index)
            bound_jobs.append(bound_job)
            summaries.extend(job_summaries)
            errors.extend(job_errors)

    # 하나라도 binding이 불완전하면 일부 조회만 먼저 실행되는 일을 막기 위해 모든 job을 검증 불가 상태로 바꿉니다.
    # 다음 06 검증기가 이 source_type을 거부하므로 broad query가 실제 어댑터까지 도달하지 않습니다.
    if errors:
        plan["retrieval_jobs"] = [_blocked_job(job) for job in jobs]
    else:
        plan["retrieval_jobs"] = bound_jobs
    payload["intent_plan"] = plan

    trace = payload.setdefault("trace", {})
    trace.setdefault("errors", []).extend(deepcopy(errors))
    status = "error" if errors else "ok"
    _record_inspection(payload, status, summaries, errors)
    orchestration["binding_status"] = status
    orchestration["bound_job_count"] = len(bound_jobs) if not errors else 0
    payload["orchestration"] = orchestration
    return payload


# 함수 설명: `_bind_job()`은 단일 신뢰 조회 작업의 binding 목록을 검증하고 충돌 없이 파라미터를 채웁니다.
def _bind_job(
    job: dict[str, Any],
    upstream_rows: list[Any],
    job_index: int,
) -> tuple[dict[str, Any], list[dict[str, Any]], list[dict[str, Any]]]:
    next_job = deepcopy(job)
    dataset_key = str(next_job.get("dataset_key") or "").strip()
    if next_job.get("trusted_catalog") is not True:
        return next_job, [], [
            _issue(
                "untrusted_upstream_binding",
                "신뢰 카탈로그에서 구성되지 않은 조회 작업에는 상위 결과를 연결할 수 없습니다.",
                dataset_key=dataset_key,
                index=job_index,
            )
        ]

    source_config = next_job.get("source_config") if isinstance(next_job.get("source_config"), dict) else {}
    bindings = source_config.get("upstream_bindings")
    if not isinstance(bindings, list) or not bindings:
        return next_job, [], [
            _issue(
                "upstream_binding_missing",
                "table catalog source_config에 upstream_bindings가 없어 상위 결과 기반 조회를 차단했습니다.",
                dataset_key=dataset_key,
                index=job_index,
            )
        ]

    params = deepcopy(next_job.get("required_params")) if isinstance(next_job.get("required_params"), dict) else {}
    summaries: list[dict[str, Any]] = []
    errors: list[dict[str, Any]] = []
    target_params: set[str] = set()

    for binding_index, binding in enumerate(bindings):
        if not isinstance(binding, dict):
            errors.append(
                _issue(
                    "invalid_upstream_binding",
                    "upstream_bindings 항목은 object여야 합니다.",
                    dataset_key=dataset_key,
                    index=job_index,
                    binding_index=binding_index,
                )
            )
            continue
        binding_errors, summary, target_param, bound_value = _resolve_binding(
            binding,
            upstream_rows,
            dataset_key,
            job_index,
            binding_index,
        )
        errors.extend(binding_errors)
        if binding_errors:
            continue
        target_marker = target_param.casefold()
        if target_marker in target_params:
            errors.append(
                _issue(
                    "ambiguous_upstream_binding",
                    f"같은 target_param에 둘 이상의 binding이 선언되었습니다: {target_param}",
                    dataset_key=dataset_key,
                    index=job_index,
                    binding_index=binding_index,
                )
            )
            continue
        target_params.add(target_marker)
        existing_key = _dict_key_ci(params, target_param)
        if existing_key and not _same_value(params.get(existing_key), bound_value):
            errors.append(
                _issue(
                    "upstream_parameter_conflict",
                    f"기존 required_params 값과 상위 결과 binding 값이 충돌합니다: {target_param}",
                    dataset_key=dataset_key,
                    index=job_index,
                    binding_index=binding_index,
                )
            )
            continue
        params[existing_key or target_param] = deepcopy(bound_value)
        summaries.append(summary)

    if not errors:
        next_job["required_params"] = params
        next_job["upstream_binding_applied"] = True
        next_job["upstream_source_alias"] = UPSTREAM_SOURCE_ALIAS
    return next_job, summaries, errors


# 함수 설명: `_resolve_binding()`은 한 binding의 컬럼·연산자·최대값을 검사하고 실제 주입 값과 추적 요약을 반환합니다.
def _resolve_binding(
    binding: dict[str, Any],
    upstream_rows: list[Any],
    dataset_key: str,
    job_index: int,
    binding_index: int,
) -> tuple[list[dict[str, Any]], dict[str, Any], str, Any]:
    entity_type = str(binding.get("entity_type") or "").strip()
    source_column = str(binding.get("source_column") or "").strip()
    target_param = str(binding.get("target_param") or "").strip()
    source_alias = str(binding.get("source_alias") or UPSTREAM_SOURCE_ALIAS).strip()
    operator = str(binding.get("operator") or "in").strip().lower()
    location = {"dataset_key": dataset_key, "index": job_index, "binding_index": binding_index}
    errors: list[dict[str, Any]] = []

    if not entity_type or not source_column or not target_param:
        errors.append(
            _issue(
                "invalid_upstream_binding",
                "upstream binding에는 entity_type, source_column, target_param이 모두 필요합니다.",
                **location,
            )
        )
    if source_alias != UPSTREAM_SOURCE_ALIAS:
        errors.append(
            _issue(
                "unsupported_upstream_source_alias",
                f"현재 지원하는 상위 source alias는 {UPSTREAM_SOURCE_ALIAS} 하나입니다.",
                **location,
            )
        )
    if operator not in SUPPORTED_OPERATORS:
        errors.append(
            _issue(
                "unsupported_upstream_operator",
                f"지원하지 않는 upstream binding operator입니다: {operator}",
                **location,
            )
        )
    if errors:
        return errors, {}, target_param, None

    actual_columns = _matching_columns(upstream_rows, source_column)
    if not actual_columns:
        return [
            _issue(
                "upstream_source_column_missing",
                f"상위 결과에 binding source_column이 없습니다: {source_column}",
                **location,
            )
        ], {}, target_param, None
    if len(actual_columns) > 1:
        return [
            _issue(
                "ambiguous_upstream_source_column",
                f"대소문자만 다른 상위 결과 컬럼이 둘 이상 존재합니다: {', '.join(actual_columns)}",
                **location,
            )
        ], {}, target_param, None

    values, invalid_value = _unique_scalar_values(upstream_rows, actual_columns[0])
    if invalid_value:
        return [
            _issue(
                "invalid_upstream_entity_value",
                f"상위 식별자 컬럼에 scalar가 아닌 값이 포함되어 있습니다: {actual_columns[0]}",
                **location,
            )
        ], {}, target_param, None
    if not values:
        return [
            _issue(
                "upstream_entity_values_missing",
                f"상위 식별자 컬럼에 전달할 값이 없습니다: {actual_columns[0]}",
                **location,
            )
        ], {}, target_param, None

    max_values = _max_values(binding.get("max_values"))
    if len(values) > max_values:
        return [
            _issue(
                "upstream_entity_limit_exceeded",
                f"상위 식별자 {len(values)}개가 catalog 상한 {max_values}개를 초과했습니다.",
                value_count=len(values),
                max_values=max_values,
                **location,
            )
        ], {}, target_param, None
    if operator == "eq" and len(values) != 1:
        return [
            _issue(
                "ambiguous_upstream_entity_value",
                f"eq binding에는 식별자가 정확히 1개여야 하지만 {len(values)}개입니다.",
                value_count=len(values),
                **location,
            )
        ], {}, target_param, None

    bound_value = values[0] if operator == "eq" else values
    summary = {
        "dataset_key": dataset_key,
        "entity_type": entity_type,
        "source_alias": source_alias,
        "source_column": actual_columns[0],
        "target_param": target_param,
        "operator": operator,
        "value_count": len(values),
        "max_values": max_values,
    }
    return [], summary, target_param, bound_value


# 함수 설명: `_matching_columns()`는 전체 상위 행에서 요청 컬럼과 대소문자 무시 기준으로 일치하는 실제 컬럼명을 찾습니다.
def _matching_columns(rows: list[Any], requested: str) -> list[str]:
    result: list[str] = []
    marker = requested.casefold()
    for row in rows:
        if not isinstance(row, dict):
            continue
        for key in row:
            text = str(key)
            if text.casefold() == marker and text not in result:
                result.append(text)
    return result


# 함수 설명: `_unique_scalar_values()`는 순서를 유지하며 중복을 제거하고 dict/list 같은 위험한 파라미터 값은 거부합니다.
def _unique_scalar_values(rows: list[Any], column: str) -> tuple[list[Any], bool]:
    result: list[Any] = []
    seen: set[str] = set()
    for row in rows:
        if not isinstance(row, dict):
            continue
        value = row.get(column)
        if value is None or (isinstance(value, str) and not value.strip()):
            continue
        if isinstance(value, (dict, list, tuple, set)):
            return [], True
        marker = json.dumps(value, ensure_ascii=False, sort_keys=True, default=str)
        if marker in seen:
            continue
        seen.add(marker)
        result.append(value)
    return result, False


# 함수 설명: `_blocked_job()`은 binding 오류가 난 요청이 실제 source 어댑터에 도달하지 않도록 06 검증기에서 거부될 표시를 남깁니다.
def _blocked_job(job: dict[str, Any]) -> dict[str, Any]:
    blocked = deepcopy(job)
    blocked["upstream_binding_original_source_type"] = blocked.get("source_type")
    blocked["source_type"] = BLOCKED_SOURCE_TYPE
    blocked["upstream_binding_blocked"] = True
    return blocked


# 함수 설명: `_max_values()`는 catalog 설정값을 보수적인 기본값과 절대 상한 안의 양의 정수로 정규화합니다.
def _max_values(value: Any) -> int:
    try:
        parsed = int(str(value).strip()) if str(value or "").strip() else DEFAULT_MAX_VALUES
    except Exception:
        parsed = DEFAULT_MAX_VALUES
    return max(1, min(parsed, MAX_ALLOWED_VALUES))


# 함수 설명: `_dict_key_ci()`는 required_params 안에서 대소문자만 다른 기존 키를 찾아 중복 키 생성을 막습니다.
def _dict_key_ci(value: dict[str, Any], key: str) -> str:
    marker = key.casefold()
    for existing in value:
        if str(existing).casefold() == marker:
            return str(existing)
    return ""


# 함수 설명: `_same_value()`는 기존 파라미터와 binding 값이 의미상 같은 JSON 값인지 비교합니다.
def _same_value(left: Any, right: Any) -> bool:
    return json.dumps(left, ensure_ascii=False, sort_keys=True, default=str) == json.dumps(
        right,
        ensure_ascii=False,
        sort_keys=True,
        default=str,
    )


# 함수 설명: `_record_inspection()`은 실제 식별자 값을 복제하지 않고 적용 건수와 오류만 trace에 기록합니다.
def _record_inspection(
    payload: dict[str, Any],
    status: str,
    summaries: list[dict[str, Any]],
    errors: list[dict[str, Any]],
    reason: str = "",
) -> None:
    payload.setdefault("trace", {}).setdefault("inspection", {})["upstream_parameter_binding"] = {
        "stage": "05a_upstream_entity_parameter_binder",
        "status": status,
        "reason": reason,
        "binding_count": len(summaries),
        "bindings": deepcopy(summaries),
        "error_count": len(errors),
        "errors": deepcopy(errors),
    }


# 함수 설명: `_issue()`는 binding 오류를 표준 type/message와 위치 정보가 있는 dict로 만듭니다.
def _issue(issue_type: str, message: str, **extra: Any) -> dict[str, Any]:
    return {"type": issue_type, "message": message, **extra}


# 함수 설명: `_ref_id()`는 문자열 또는 표준 data_ref object에서 실제 MongoDB 참조 ID를 추출합니다.
def _ref_id(value: Any) -> str:
    if isinstance(value, dict):
        return str(value.get("ref_id") or value.get("data_ref") or value.get("_id") or "").strip()
    return str(value or "").strip()


# 함수 설명: `_payload()`는 입력 Data를 독립적으로 수정할 수 있도록 표준 dict 복사본으로 변환합니다.
def _payload(value: Any) -> dict[str, Any]:
    data = getattr(value, "data", value)
    return deepcopy(data) if isinstance(data, dict) else {}


# Langflow 컴포넌트 클래스: standalone 캔버스에서 한 입력·한 출력의 결정론적 파라미터 바인딩 노드로 사용합니다.
class UpstreamEntityParameterBinder(Component):
    display_name = "05A 상위 결과 파라미터 바인더"
    description = "상위 분석 결과의 식별자를 신뢰 카탈로그 규칙으로 다음 조회 작업 파라미터에 연결합니다."
    inputs = [DataInput(name="payload", display_name="페이로드", required=True)]
    outputs = [Output(name="payload_out", display_name="페이로드 출력", method="build_payload")]

    # Langflow 출력 함수: binding 검증과 주입이 완료된 단일 페이로드를 다음 조회 검증기로 전달합니다.
    def build_payload(self) -> Data:
        return Data(data=bind_upstream_entity_parameters(getattr(self, "payload", None)))

