# =============================================================================
# 컴포넌트 개요: 09 Oracle 쿼리 조회기
# 역할: table catalog의 Oracle source_config와 Oracle 설정/TNS를 사용해 실제 SQL 조회를 실행합니다.
# 주요 입력: 페이로드 (payload) · 필수, Oracle 설정/TNS (oracle_config), 조회 제한 건수 (fetch_limit)
# 주요 출력: 조회 페이로드 (retrieval_payload)
# 처리 흐름: 카탈로그의 SQL 템플릿과 파라미터를 검증하고 Oracle 연결·조회·행 변환·오류 표준화를 한 경계에서 처리합니다.
# 유지보수 포인트: 실행 오류를 다른 source의 성공처럼 위장하는 과도한 fallback은 만들지 말고 공통 errors 계약으로 전달합니다.
# =============================================================================

from __future__ import annotations

import ast
import importlib.util
import json
import os
import re
import subprocess
import sys
from copy import deepcopy
from datetime import date, datetime
from decimal import Decimal
from importlib import import_module
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, MessageTextInput, Output
from lfx.schema.data import Data


SINGLE_ORACLE_CONFIG_KEY = "__single_oracle_config__"
PREVIEW_LIMIT = 5


# 주요 함수: Oracle SQL 작업을 실행하고 결과 행 또는 표준 오류를 반환합니다.
# Langflow 클래스와 단위 테스트가 같은 업무 규칙을 쓰도록 일반 Python 값 중심으로 처리합니다.
def retrieve_oracle_data(payload_value: Any, oracle_config: Any = "", fetch_limit: Any = "") -> dict[str, Any]:
    payload = _payload(payload_value)
    jobs = _jobs_for_source(payload)
    if not jobs:
        return _skipped("oracle", "no oracle retrieval jobs")

    config_value = oracle_config or os.getenv("ORACLE_CONFIG_JSON", "")
    limit = _fetch_limit(fetch_limit or os.getenv("SOURCE_FETCH_LIMIT", "5000"))
    config, config_errors = _oracle_config_from_value(config_value)
    if config_errors:
        results = [_error_result(job, "invalid_oracle_config", f"Oracle 설정/TNS 파싱 실패: {'; '.join(config_errors)}") for job in jobs]
    elif not _config_has_values(config):
        results = [_error_result(job, "missing_oracle_config", "Oracle 설정/TNS가 비어 있어 실제 조회를 실행할 수 없습니다.") for job in jobs]
    else:
        oracle_module = getattr(OracleQueryRetriever, "oracledb", None) if "OracleQueryRetriever" in globals() else None
        results = [_run_oracle_job(job, config, limit, oracle_module) for job in jobs]

    errors = [error for result in results for error in result.get("errors", []) if isinstance(error, dict)]
    warnings = [warning for result in results for warning in result.get("warnings", []) if isinstance(warning, dict)]
    return {
        "source_type": "oracle",
        "status": "error" if errors else "ok",
        "skipped": False,
        "executed_jobs": [str(job.get("job_id") or job.get("dataset_key") or index) for index, job in enumerate(jobs, 1)],
        "source_results": results,
        "errors": errors,
        "warnings": warnings,
    }


# 주요 함수: 선택적 외부 패키지를 확인하고 허용된 경우에만 준비합니다.
# Langflow 클래스와 단위 테스트가 같은 업무 규칙을 쓰도록 일반 Python 값 중심으로 처리합니다.
def ensure_package(package_name: str, import_name: str | None = None) -> None:
    module_name = import_name or package_name
    if importlib.util.find_spec(module_name) is None:
        subprocess.check_call([sys.executable, "-m", "pip", "install", "--trusted-host", "nexus.skhynix.com", package_name])


# 함수 설명: `_run_oracle_job()`는 oracle·조회 작업 실행 경계를 담당하고 성공 결과와 오류를 공통 계약으로 반환합니다.
def _run_oracle_job(job: dict[str, Any], oracle_config: dict[str, Any], fetch_limit: int, oracle_module: Any | None = None) -> dict[str, Any]:
    source_config = _source_config(job)
    params = _job_params(job)
    missing = _missing_required_params(params, _required_param_names(job, source_config))
    if missing:
        return _error_result(job, "missing_required_params", f"필수 파라미터가 없습니다: {', '.join(missing)}", params=params)

    query_template = str(
        source_config.get("query_template")
        or source_config.get("sql_template")
        or source_config.get("oracle_sql")
        or source_config.get("sql")
        or source_config.get("query")
        or ""
    ).strip()
    if not query_template:
        return _error_result(job, "missing_query_template", "Oracle source_config에 query_template이 없습니다.", params=params)

    sql, missing_template_params = _render_template(query_template, params)
    if missing_template_params:
        return _error_result(job, "missing_template_params", f"SQL 템플릿 파라미터가 없습니다: {', '.join(missing_template_params)}", params=params)

    db_key = str(source_config.get("db_key") or job.get("db_key") or "").strip()
    if not db_key:
        return _error_result(job, "missing_db_key", "Oracle source_config에 db_key가 없습니다.", params=params)

    try:
        connector = OracleConnector(oracle_config, oracle_module)
        rows = connector.execute_query(db_key, sql, fetch_limit=fetch_limit)
        columns = getattr(connector, "last_columns", [])
        rows = _json_ready(rows)
        if not isinstance(rows, list):
            rows = []
        return _standard_result(job, rows, params, db_key, sql, columns=columns)
    except Exception as exc:
        return _error_result(job, "oracle_retrieval_failed", f"Oracle 조회 실패: {exc}", params=params)


# 내부 연동 도우미 클래스: 외부 라이브러리나 클라이언트 차이를 이 파일의 표준 호출 형태로 감쌉니다.
class OracleConnector:
    # 함수 설명: `__init__()`는 외부 클라이언트나 실행 설정을 인스턴스에 보관해 뒤의 메서드가 같은 연결 문맥을 사용하게 합니다.
    def __init__(self, config: dict[str, Any], oracle_module: Any | None = None):
        self.config = config
        self.oracle_module = oracle_module
        self.last_columns: list[str] = []

    # 함수 설명: `_oracledb()`는 테스트에서 주입된 Oracle driver를 우선 사용하고 없으면 실제 oracledb 모듈을 준비합니다.
    def _oracledb(self) -> Any:
        if self.oracle_module is not None:
            return self.oracle_module
        ensure_package("oracledb")
        self.oracle_module = import_module("oracledb")
        return self.oracle_module

    # 주요 메서드: 설정에서 Oracle 연결 객체를 만들고 호출자에게 반환합니다.
    # Langflow의 동적 빌드 또는 공개 실행 계약에서 호출될 수 있으므로 이름과 반환형을 유지합니다.
    def get_connection(self, target_db: str) -> Any:
        resolved = next((key for key in self.config if _normalize_key(key) == _normalize_key(target_db)), "")
        if not resolved and len(self.config) == 1:
            resolved = next(iter(self.config))
        if not resolved:
            raise ValueError(f"알 수 없는 Oracle DB 설정입니다: {target_db}")
        db_conf = self.config[resolved] if isinstance(self.config.get(resolved), dict) else {}
        user = str(db_conf.get("user") or db_conf.get("username") or db_conf.get("id") or "").strip()
        password = str(db_conf.get("password") or db_conf.get("pw") or "").strip()
        dsn = str(db_conf.get("dsn") or db_conf.get("tns") or db_conf.get("tns_name") or db_conf.get("tns_alias") or "").strip()
        if not dsn:
            raise ValueError(f"{target_db} Oracle 설정에 dsn/tns가 없습니다.")
        if user and password:
            return self._oracledb().connect(user=user, password=password, dsn=dsn)
        return self._oracledb().connect(dsn=dsn)

    # 주요 메서드: Oracle cursor 실행 결과를 컬럼명 기반 dict 행으로 변환합니다.
    # Langflow의 동적 빌드 또는 공개 실행 계약에서 호출될 수 있으므로 이름과 반환형을 유지합니다.
    def execute_query(self, target_db: str, sql: str, fetch_limit: int | None = None) -> list[dict[str, Any]]:
        conn = None
        cursor = None
        try:
            conn = self.get_connection(target_db)
            cursor = conn.cursor()
            cursor.execute(sql)
            columns = [column[0] for column in cursor.description]
            self.last_columns = [str(column) for column in columns]
            rows = cursor.fetchmany(fetch_limit) if fetch_limit else cursor.fetchall()
            return [dict(zip(columns, row)) for row in rows]
        finally:
            if cursor:
                cursor.close()
            if conn:
                conn.close()


# 함수 설명: `_jobs_for_source()`는 전체 조회 작업 중 지정한 source type에 해당하는 작업만 골라냅니다.
def _jobs_for_source(payload: dict[str, Any]) -> list[dict[str, Any]]:
    bundle = payload.get("retrieval_job_bundle") if isinstance(payload.get("retrieval_job_bundle"), dict) else {}
    bundle_jobs = bundle.get("jobs") if isinstance(bundle.get("jobs"), list) else []
    if bundle_jobs:
        return [deepcopy(job) for job in bundle_jobs if isinstance(job, dict)]
    plan = payload.get("intent_plan") if isinstance(payload.get("intent_plan"), dict) else {}
    jobs = plan.get("retrieval_jobs") if isinstance(plan.get("retrieval_jobs"), list) else []
    return [deepcopy(job) for job in jobs if isinstance(job, dict) and _source_type(job.get("source_type")) in {"oracle", "oracle_db", "oracledb"}]


# 함수 설명: `_source_config()`는 조회 작업 또는 카탈로그에서 허용된 데이터 소스 설정만 dict로 꺼냅니다.
def _source_config(job: dict[str, Any]) -> dict[str, Any]:
    config = deepcopy(job.get("source_config")) if isinstance(job.get("source_config"), dict) else {}
    for key in ("db_key", "query_template", "sql_template", "oracle_sql", "sql", "query"):
        if job.get(key) not in (None, "", [], {}):
            config.setdefault(key, deepcopy(job[key]))
    return config


# 함수 설명: `_job_params()`는 조회 작업의 params를 안전한 dict로 정리해 retriever에 전달합니다.
def _job_params(job: dict[str, Any]) -> dict[str, Any]:
    if isinstance(job.get("params"), dict):
        return deepcopy(job["params"])
    if isinstance(job.get("required_params"), dict):
        return deepcopy(job["required_params"])
    return {}


# 함수 설명: `_required_param_names()`는 카탈로그 설정에서 실행 전에 반드시 있어야 하는 파라미터 이름을 추출합니다.
def _required_param_names(job: dict[str, Any], source_config: dict[str, Any]) -> list[Any]:
    if isinstance(source_config.get("required_params"), (list, tuple, set)):
        return _as_list(source_config.get("required_params"))
    if isinstance(job.get("required_param_names"), (list, tuple, set)):
        return _as_list(job.get("required_param_names"))
    if not isinstance(job.get("required_params"), dict):
        return _as_list(job.get("required_params"))
    return []


# 함수 설명: `_standard_result()`는 정상 조회 결과를 dataset/source alias와 rows가 포함된 공통 결과 구조로 만듭니다.
def _standard_result(job: dict[str, Any], rows: list[dict[str, Any]], params: dict[str, Any], db_key: str, sql: str, columns: list[str] | None = None) -> dict[str, Any]:
    result_columns = _rows_columns(rows) or _string_list(columns)
    return {
        "source_alias": job.get("source_alias") or job.get("dataset_key"),
        "dataset_key": job.get("dataset_key"),
        "source_type": "oracle",
        "status": "ok",
        "row_count": len(rows),
        "columns": result_columns,
        "preview_rows": rows[:PREVIEW_LIMIT],
        "rows": rows,
        "applied_params": deepcopy(params),
        "pandas_filters": deepcopy(job.get("filters", {})),
        "data_ref": "",
        "source_execution": {
            "used_dummy_data": False,
            "adapter": "oracle",
            "db_key": db_key,
            "executed_query": sql,
            "source_configured": True,
            "filters_applied_in_retriever": False,
        },
        "warnings": [],
        "errors": [],
    }


# 함수 설명: `_error_result()`는 예외 정보를 공통 errors 배열과 status가 포함된 실패 결과 구조로 만듭니다.
def _error_result(job: dict[str, Any], error_type: str, message: str, params: dict[str, Any] | None = None) -> dict[str, Any]:
    error = {"type": error_type, "message": message, "dataset_key": job.get("dataset_key", "")}
    return {
        "source_alias": job.get("source_alias") or job.get("dataset_key"),
        "dataset_key": job.get("dataset_key"),
        "source_type": "oracle",
        "status": "error",
        "row_count": 0,
        "columns": [],
        "preview_rows": [],
        "rows": [],
        "applied_params": deepcopy(params if params is not None else _job_params(job)),
        "pandas_filters": deepcopy(job.get("filters", {})),
        "data_ref": "",
        "source_execution": {"used_dummy_data": False, "adapter": "oracle", "source_configured": False},
        "warnings": [],
        "errors": [error],
    }


# 함수 설명: `_skipped()`는 설정이나 대상 작업이 없어 실행하지 않은 이유를 표준 skipped 결과로 남깁니다.
def _skipped(source_type: str, reason: str) -> dict[str, Any]:
    return {"source_type": source_type, "status": "skipped", "skipped": True, "skip_reason": reason, "source_results": [], "errors": [], "warnings": []}


# 함수 설명: `_oracle_config_from_value()`는 dict·JSON·TNS 텍스트 입력을 DB key별 Oracle 연결 설정으로 변환합니다.
def _oracle_config_from_value(value: Any) -> tuple[dict[str, Any], list[str]]:
    if value in (None, "", {}, []):
        return {}, []
    parsed, errors = _parse_jsonish(value)
    if isinstance(parsed, dict) and isinstance(parsed.get("oracle_config"), dict):
        parsed = parsed["oracle_config"]
    if isinstance(parsed, dict) and parsed:
        return parsed, []
    text = str(value or "").strip()
    named_tns = _parse_named_tns_blocks(text)
    if named_tns:
        return named_tns, []
    if _looks_like_tns(text):
        return {SINGLE_ORACLE_CONFIG_KEY: {"tns": text}}, []
    if errors and not parsed:
        return {}, errors
    return {}, ["Oracle 설정은 JSON 객체 또는 TNS block이어야 합니다."]


# 함수 설명: `_parse_jsonish()`는 복합 입력이나 응답에서 jsonish을 찾아 검증 가능한 기본 Python 값으로 변환합니다.
def _parse_jsonish(value: Any) -> tuple[Any, list[str]]:
    if isinstance(value, (dict, list)):
        return deepcopy(value), []
    text = str(value or "").strip()
    if not text:
        return {}, []
    errors: list[str] = []
    for parser in (json.loads, ast.literal_eval):
        try:
            return parser(text), []
        except Exception as exc:
            errors.append(str(exc))
    normalized = _normalize_triple_quoted_json(text)
    if normalized != text:
        for parser in (json.loads, ast.literal_eval):
            try:
                return parser(normalized), []
            except Exception as exc:
                errors.append(str(exc))
    return {}, errors


# 함수 설명: `_normalize_triple_quoted_json()`는 triple·quoted·JSON의 표기·자료형 차이를 비교와 저장에 사용할 표준 형태로 정규화합니다.
def _normalize_triple_quoted_json(text: str) -> str:
    return re.sub(r'("""|\'\'\')(.*?)(\1)', lambda match: json.dumps(match.group(2)), str(text or ""), flags=re.DOTALL)


# 함수 설명: `_looks_like_tns()`는 입력값이 LIKE·TNS 조건에 해당하는지 부작용 없이 bool로 판정합니다.
def _looks_like_tns(text: str) -> bool:
    upper_text = str(text or "").upper()
    return "(DESCRIPTION=" in upper_text or ("(ADDRESS=" in upper_text and "(CONNECT_DATA=" in upper_text)


# 함수 설명: `_parse_named_tns_blocks()`는 복합 입력이나 응답에서 named·TNS·blocks을 찾아 검증 가능한 기본 Python 값으로 변환합니다.
def _parse_named_tns_blocks(text: str) -> dict[str, Any]:
    configs: dict[str, Any] = {}
    current_key = ""
    current_lines: list[str] = []

    # 함수 설명: `save_current()`는 현재까지 읽은 TNS alias와 여러 줄 설정을 완성된 설정 항목으로 저장하고 버퍼를 초기화합니다.
    def save_current() -> None:
        nonlocal current_key, current_lines
        tns = "\n".join(current_lines).strip()
        if current_key and _looks_like_tns(tns):
            configs[current_key] = {"tns": tns}
        current_key = ""
        current_lines = []

    for raw_line in str(text or "").splitlines():
        line = raw_line.strip()
        key_match = re.match(r"^([A-Za-z][A-Za-z0-9_-]*)\s*:\s*(.*)$", line)
        if key_match and not line.startswith("("):
            save_current()
            current_key = key_match.group(1).strip()
            possible_tns = key_match.group(2).strip()
            if possible_tns:
                current_lines.append(possible_tns)
            continue
        if current_key:
            current_lines.append(raw_line)
    save_current()
    return configs


# 함수 설명: `_render_template()`는 검증된 파라미터를 SQL·URL·본문 템플릿에 치환해 실제 요청 문자열을 만듭니다.
def _render_template(template: str, params: dict[str, Any]) -> tuple[str, list[str]]:
    missing: list[str] = []

    # 함수 설명: `replace()`는 Oracle SQL 템플릿 placeholder를 자료형에 맞는 SQL literal로 치환하고 누락 key를 기록합니다.
    def replace(match: re.Match[str]) -> str:
        key = match.group(1).strip()
        value = _dict_get_ci(params, key)
        if value in (None, "", []):
            missing.append(key)
            return match.group(0)
        return _sql_literal(value)

    return re.sub(r"\{([^{}]+)\}", replace, str(template or "")), missing


# 함수 설명: `_sql_literal()`는 SQL 템플릿 파라미터를 자료형에 맞는 안전한 literal 표현으로 변환합니다.
def _sql_literal(value: Any) -> str:
    if value is None:
        return "NULL"
    if isinstance(value, (list, tuple, set)):
        return ", ".join(_sql_literal(item) for item in value)
    if isinstance(value, (datetime, date)):
        return f"'{value.strftime('%Y%m%d')}'"
    if isinstance(value, Decimal):
        return str(value)
    if isinstance(value, (int, float)) and not isinstance(value, bool):
        return str(value)
    return "'" + str(value).replace("'", "''") + "'"


# 함수 설명: `_missing_required_params()`는 필수 파라미터 중 실제 작업 값에 없는 항목을 찾아 오류 목록으로 반환합니다.
def _missing_required_params(params: dict[str, Any], required_params: Any) -> list[str]:
    missing = []
    for item in _as_list(required_params):
        key = str(item or "").strip()
        if key and _dict_get_ci(params, key) in (None, "", []):
            missing.append(key)
    return missing


# 함수 설명: `_rows_columns()`는 행 목록과 명시 컬럼을 함께 정규화해 표준 rows/columns 쌍을 만듭니다.
def _rows_columns(rows: list[dict[str, Any]]) -> list[str]:
    columns: list[str] = []
    for row in rows:
        for key in row:
            text = str(key)
            if text not in columns:
                columns.append(text)
    return columns


# 함수 설명: `_string_list()`는 여러 형태의 입력에서 비어 있지 않은 문자열만 뽑아 중복 없는 목록으로 정리합니다.
def _string_list(value: Any) -> list[str]:
    return [str(item) for item in value if str(item or "").strip()] if isinstance(value, list) else []


# 함수 설명: `_json_ready()`는 datetime·Decimal·NaN 등 JSON이 직접 표현하지 못하는 값을 안전한 기본형으로 재귀 변환합니다.
def _json_ready(value: Any) -> Any:
    if value is None or isinstance(value, (str, int, float, bool)):
        return value
    if isinstance(value, (datetime, date)):
        return value.isoformat()
    if isinstance(value, Decimal):
        return float(value)
    if isinstance(value, dict):
        return {str(key): _json_ready(item) for key, item in value.items()}
    if isinstance(value, (list, tuple, set)):
        return [_json_ready(item) for item in value]
    try:
        if value != value:
            return None
    except Exception:
        pass
    return str(value)


# 함수 설명: `_fetch_limit()`는 설정된 조회 제한을 안전한 정수 범위로 보정합니다.
def _fetch_limit(value: Any) -> int:
    try:
        return max(1, int(value or 5000))
    except Exception:
        return 5000


# 함수 설명: `_config_has_values()`는 Oracle 설정 dict에 실제 접속값이 하나 이상 존재하는지 판정합니다.
def _config_has_values(config: Any) -> bool:
    return isinstance(config, dict) and any(value not in (None, "", [], {}) for value in config.values())


# 함수 설명: `_source_type()`는 조회 작업의 source type을 표준 소문자 식별자로 정규화합니다.
def _source_type(value: Any) -> str:
    return str(value or "").strip().lower().replace("-", "_").replace(" ", "_")


# 함수 설명: `_normalize_key()`는 key의 대소문자·공백·구분자 차이를 제거해 비교 가능한 표준 식별자로 바꿉니다.
def _normalize_key(value: Any) -> str:
    return re.sub(r"[\s_-]+", "", str(value or "").strip().lower())


# 함수 설명: `_dict_get_ci()`는 키의 대소문자 차이를 무시하고 dict에서 요청한 값을 찾습니다.
def _dict_get_ci(mapping: dict[str, Any], key: Any, default: Any = None) -> Any:
    if not isinstance(mapping, dict):
        return default
    text = str(key or "").strip()
    if text in mapping:
        return mapping[text]
    normalized = _normalize_key(text)
    for item_key, value in mapping.items():
        if _normalize_key(item_key) == normalized:
            return value
    return default


# 함수 설명: `_as_list()`는 단일 값과 여러 값 입력을 모두 같은 list 형태로 맞춰 반복 처리를 단순화합니다.
def _as_list(value: Any) -> list[Any]:
    if value is None:
        return []
    if isinstance(value, list):
        return value
    if isinstance(value, tuple):
        return list(value)
    if isinstance(value, set):
        return list(value)
    return [value]


# 함수 설명: `_payload()`는 Langflow Data/Message 또는 일반 dict 입력에서 안전한 dict 페이로드 복사본을 꺼냅니다.
def _payload(value: Any) -> dict[str, Any]:
    if isinstance(value, dict):
        return deepcopy(value)
    data = getattr(value, "data", None)
    return deepcopy(data) if isinstance(data, dict) else {}


# Langflow 컴포넌트 클래스: inputs/outputs가 캔버스 포트와 JSON edge 계약을 정의합니다.
# 실제 업무 규칙은 위의 주요 함수에 두어 UI 실행과 단위 테스트가 같은 로직을 사용합니다.
class OracleQueryRetriever(Component):
    oracledb = None

    display_name = "09 Oracle 쿼리 조회기"
    description = "table catalog의 Oracle source_config와 Oracle 설정/TNS를 사용해 실제 SQL 조회를 실행합니다."
    inputs = [
        DataInput(name="payload", display_name="페이로드", required=True),
        MessageTextInput(name="oracle_config", display_name="Oracle 설정/TNS", required=False, value=""),
        MessageTextInput(name="fetch_limit", display_name="조회 제한 건수", required=False, value="5000", advanced=True),
    ]
    outputs = [Output(name="retrieval_payload", display_name="조회 페이로드", method="build_payload")]

    # Langflow 출력 함수: '조회 페이로드 (retrieval_payload)' 포트가 요청될 때 실행됩니다.
    # 핵심 처리 결과를 Langflow Data/Message 형식으로 감싸 다음 노드에 전달합니다.
    def build_payload(self) -> Data:
        return Data(data=retrieve_oracle_data(getattr(self, "payload", None), getattr(self, "oracle_config", ""), getattr(self, "fetch_limit", "")))

# -*- coding: utf-8 -*-
# =============================================================================
# 컴포넌트 개요: 10 H-API 데이터 조회기
# 역할: table catalog의 H-API source_config를 사용해 실제 API 조회를 실행합니다.
# 주요 입력: 페이로드 (payload) · 필수, H-API 토큰 (api_token), 요청 제한 시간(초) (timeout_seconds), 조회 제한 건수 (fetch_limit)
# 주요 출력: 조회 페이로드 (retrieval_payload)
# 처리 흐름: 카탈로그 설정으로 HTTP 요청을 만들고 응답 경로에서 행을 추출해 공통 source result 형식으로 반환합니다.
# 유지보수 포인트: 실행 오류를 다른 source의 성공처럼 위장하는 과도한 fallback은 만들지 말고 공통 errors 계약으로 전달합니다.
# =============================================================================

from __future__ import annotations

import json
import os
import re
import urllib.error
import urllib.parse
import urllib.request
from copy import deepcopy
from datetime import date, datetime
from decimal import Decimal
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, MessageTextInput, Output
from lfx.schema.data import Data


PREVIEW_LIMIT = 5


# 주요 함수: HTTP API 작업을 실행하고 지정된 응답 경로에서 결과 행을 꺼냅니다.
# Langflow 클래스와 단위 테스트가 같은 업무 규칙을 쓰도록 일반 Python 값 중심으로 처리합니다.
def h_api_retrieve(
    payload_value: Any,
    api_token: Any = "",
    timeout_seconds: Any = "",
    fetch_limit: Any = "",
    opener: Any = None,
) -> dict[str, Any]:
    payload = _payload(payload_value)
    jobs = _jobs_for_source(payload)
    if not jobs:
        return _skipped("h_api", "no h_api retrieval jobs")

    token = str(api_token or os.getenv("H_API_TOKEN", "")).strip()
    timeout = _timeout(timeout_seconds or os.getenv("H_API_TIMEOUT_SECONDS", "30"))
    limit = _fetch_limit(fetch_limit or os.getenv("SOURCE_FETCH_LIMIT", "5000"))
    results = [_run_h_api_job(job, token, timeout, limit, opener) for job in jobs]
    errors = [error for result in results for error in result.get("errors", []) if isinstance(error, dict)]
    warnings = [warning for result in results for warning in result.get("warnings", []) if isinstance(warning, dict)]
    return {
        "source_type": "h_api",
        "status": "error" if errors else "ok",
        "skipped": False,
        "executed_jobs": [str(job.get("job_id") or job.get("dataset_key") or index) for index, job in enumerate(jobs, 1)],
        "source_results": results,
        "errors": errors,
        "warnings": warnings,
    }


# 함수 설명: `_run_h_api_job()`는 H·API·조회 작업 실행 경계를 담당하고 성공 결과와 오류를 공통 계약으로 반환합니다.
def _run_h_api_job(job: dict[str, Any], api_token: str, timeout: int, fetch_limit: int, opener: Any = None) -> dict[str, Any]:
    source_config = _source_config(job)
    params = _job_params(job)
    missing = _missing_required_params(params, _required_param_names(job, source_config))
    if missing:
        return _error_result(job, "missing_required_params", f"필수 파라미터가 없습니다: {', '.join(missing)}", params=params)

    url_template = _api_url(source_config)
    if not url_template:
        return _error_result(job, "missing_api_url", "H-API source_config에 api_url/url/endpoint가 없습니다.", params=params)

    url, url_missing = _render_template(str(url_template), params, url_encode=True)
    if url_missing:
        return _error_result(job, "missing_template_params", f"URL 템플릿 파라미터가 없습니다: {', '.join(url_missing)}", params=params)

    method = str(source_config.get("method") or "GET").upper().strip()
    query_params = _merge_query_params(source_config, params, include_job_params=method == "GET")
    query_params, query_missing = _render_any(query_params, params, url_encode=False)
    if query_missing:
        return _error_result(job, "missing_template_params", f"query 파라미터 템플릿 값이 없습니다: {', '.join(query_missing)}", params=params)

    request_body = _request_body(source_config, params, method)
    request_body, body_missing = _render_any(request_body, params, url_encode=False)
    if body_missing:
        return _error_result(job, "missing_template_params", f"body 템플릿 파라미터 값이 없습니다: {', '.join(body_missing)}", params=params)

    headers = _request_headers(source_config, api_token)
    headers, header_missing = _render_any(headers, params, url_encode=False)
    if header_missing:
        return _error_result(job, "missing_template_params", f"header 템플릿 파라미터 값이 없습니다: {', '.join(header_missing)}", params=params)

    request_url = _append_query(url, query_params if isinstance(query_params, dict) else {})
    encoded_body = None
    if request_body not in (None, "", {}, []):
        encoded_body = json.dumps(_json_ready(request_body), ensure_ascii=False).encode("utf-8")
        headers.setdefault("Content-Type", "application/json; charset=utf-8")
    headers.setdefault("Accept", "application/json")

    try:
        request = urllib.request.Request(request_url, data=encoded_body, headers=headers, method=method)
        response = (opener or urllib.request.urlopen)(request, timeout=timeout)
        response_payload = _read_response_payload(response)
        rows = _extract_rows(response_payload, source_config.get("response_path"))
        rows = _json_ready(rows[:fetch_limit])
        return _standard_result(job, rows, params, method, request_url)
    except urllib.error.HTTPError as exc:
        detail = _safe_decode(exc.read()) if hasattr(exc, "read") else str(exc)
        return _error_result(job, "h_api_http_error", f"H-API HTTP 오류: {exc.code} {detail}", params=params)
    except Exception as exc:
        return _error_result(job, "h_api_retrieval_failed", f"H-API 조회 실패: {exc}", params=params)


# 함수 설명: `_jobs_for_source()`는 전체 조회 작업 중 지정한 source type에 해당하는 작업만 골라냅니다.
def _jobs_for_source(payload: dict[str, Any]) -> list[dict[str, Any]]:
    bundle = payload.get("retrieval_job_bundle") if isinstance(payload.get("retrieval_job_bundle"), dict) else {}
    bundle_jobs = bundle.get("jobs") if isinstance(bundle.get("jobs"), list) else []
    if bundle_jobs:
        return [deepcopy(job) for job in bundle_jobs if isinstance(job, dict)]
    plan = payload.get("intent_plan") if isinstance(payload.get("intent_plan"), dict) else {}
    jobs = plan.get("retrieval_jobs") if isinstance(plan.get("retrieval_jobs"), list) else []
    return [deepcopy(job) for job in jobs if isinstance(job, dict) and _source_type(job.get("source_type")) in {"h_api", "hapi"}]


# 함수 설명: `_source_config()`는 조회 작업 또는 카탈로그에서 허용된 데이터 소스 설정만 dict로 꺼냅니다.
def _source_config(job: dict[str, Any]) -> dict[str, Any]:
    config = deepcopy(job.get("source_config")) if isinstance(job.get("source_config"), dict) else {}
    for key in ("api_url", "url", "endpoint_url", "endpoint", "path", "method", "headers", "params", "query_params", "body", "payload"):
        if job.get(key) not in (None, "", [], {}):
            config.setdefault(key, deepcopy(job[key]))
    return config


# 함수 설명: `_api_url()`는 URL에 접근할 URL을 설정과 식별자로부터 안전하게 구성합니다.
def _api_url(source_config: dict[str, Any]) -> str:
    direct_url = str(source_config.get("api_url") or source_config.get("url") or source_config.get("endpoint_url") or "").strip()
    if direct_url:
        return direct_url
    endpoint = str(source_config.get("endpoint") or source_config.get("path") or "").strip()
    base_url = str(source_config.get("base_url") or os.getenv("H_API_BASE_URL", "")).strip()
    if not endpoint:
        return ""
    if endpoint.lower().startswith(("http://", "https://")):
        return endpoint
    return base_url.rstrip("/") + "/" + endpoint.lstrip("/") if base_url else endpoint


# 함수 설명: `_job_params()`는 조회 작업의 params를 안전한 dict로 정리해 retriever에 전달합니다.
def _job_params(job: dict[str, Any]) -> dict[str, Any]:
    if isinstance(job.get("params"), dict):
        return deepcopy(job["params"])
    if isinstance(job.get("required_params"), dict):
        return deepcopy(job["required_params"])
    return {}


# 함수 설명: `_required_param_names()`는 카탈로그 설정에서 실행 전에 반드시 있어야 하는 파라미터 이름을 추출합니다.
def _required_param_names(job: dict[str, Any], source_config: dict[str, Any]) -> list[Any]:
    if isinstance(source_config.get("required_params"), (list, tuple, set)):
        return _as_list(source_config.get("required_params"))
    if isinstance(job.get("required_param_names"), (list, tuple, set)):
        return _as_list(job.get("required_param_names"))
    if not isinstance(job.get("required_params"), dict):
        return _as_list(job.get("required_params"))
    return []


# 함수 설명: `_merge_query_params()`는 여러 쿼리·파라미터 값을 순서와 중복 정책을 지키며 하나의 결과로 합칩니다.
def _merge_query_params(source_config: dict[str, Any], params: dict[str, Any], include_job_params: bool) -> dict[str, Any]:
    query = {}
    for key in ("query_params", "params"):
        if isinstance(source_config.get(key), dict):
            query.update(deepcopy(source_config[key]))
    if include_job_params:
        for key, value in params.items():
            query.setdefault(key, deepcopy(value))
    return query


# 함수 설명: `_request_body()`는 BODY에서 현재 단계가 사용할 필드만 추출해 표준 구조로 정리합니다.
def _request_body(source_config: dict[str, Any], params: dict[str, Any], method: str) -> Any:
    for key in ("body", "payload", "json_body"):
        if source_config.get(key) not in (None, "", [], {}):
            return deepcopy(source_config[key])
    if method in {"POST", "PUT", "PATCH"}:
        return deepcopy(params)
    return None


# 함수 설명: `_request_headers()`는 headers에서 현재 단계가 사용할 필드만 추출해 표준 구조로 정리합니다.
def _request_headers(source_config: dict[str, Any], api_token: str) -> dict[str, str]:
    headers = {}
    if isinstance(source_config.get("headers"), dict):
        headers.update({str(key): str(value) for key, value in source_config["headers"].items() if value not in (None, "")})
    if api_token and not any(key.lower() == "authorization" for key in headers):
        token_header = str(source_config.get("token_header_name") or "Authorization")
        token_prefix = str(source_config.get("token_prefix") if source_config.get("token_prefix") is not None else "Bearer").strip()
        headers[token_header] = f"{token_prefix} {api_token}".strip()
    return headers


# 함수 설명: `_append_query()`는 여러 쿼리 값을 순서와 중복 정책을 지키며 하나의 결과로 합칩니다.
def _append_query(url: str, params: dict[str, Any]) -> str:
    clean_params = {key: value for key, value in params.items() if value not in (None, "", [], {})}
    if not clean_params:
        return url
    separator = "&" if urllib.parse.urlparse(url).query else "?"
    return url + separator + urllib.parse.urlencode(clean_params, doseq=True)


# 함수 설명: `_read_response_payload()`는 입력 또는 외부 저장소에서 응답·페이로드을 읽고 호출자가 사용할 형태로 반환합니다.
def _read_response_payload(response: Any) -> Any:
    raw = response.read() if hasattr(response, "read") else response
    text = _safe_decode(raw)
    if not text:
        return {}
    try:
        return json.loads(text)
    except Exception:
        return {"value": text}


# 함수 설명: `_extract_rows()`는 복합 입력이나 응답에서 행 목록을 찾아 검증 가능한 기본 Python 값으로 변환합니다.
def _extract_rows(value: Any, response_path: Any = "") -> list[dict[str, Any]]:
    selected = _select_path(value, response_path)
    rows = _rows_from_value(selected)
    return [_row_dict(row) for row in rows]


# 함수 설명: `_select_path()`는 조건과 우선순위에 맞는 PATH만 골라 원래 순서를 유지해 반환합니다.
def _select_path(value: Any, response_path: Any = "") -> Any:
    current = value
    for part in [item for item in str(response_path or "").split(".") if item]:
        if isinstance(current, dict):
            current = current.get(part)
        elif isinstance(current, list) and part.isdigit():
            current = current[int(part)]
        else:
            return None
    return current


# 함수 설명: `_rows_from_value()`는 외부 클라이언트의 DataFrame·list·dict 결과를 공통 dict 행 목록으로 변환합니다.
def _rows_from_value(value: Any) -> list[Any]:
    if isinstance(value, list):
        return value
    if isinstance(value, dict):
        for key in ("rows", "data", "items", "result", "results", "records"):
            if isinstance(value.get(key), list):
                return value[key]
            if isinstance(value.get(key), dict):
                nested = _rows_from_value(value[key])
                if nested:
                    return nested
        nested_list = _first_nested_list(value)
        if nested_list:
            return nested_list
        return [value]
    if value in (None, ""):
        return []
    return [{"value": value}]


# 함수 설명: `_first_nested_list()`는 알려진 응답 key가 없을 때 중첩 dict에서 첫 번째 행 목록 후보를 찾습니다.
def _first_nested_list(value: Any) -> list[Any]:
    if isinstance(value, dict):
        for item in value.values():
            found = _first_nested_list(item)
            if found:
                return found
    if isinstance(value, list):
        return value
    return []


# 함수 설명: `_row_dict()`는 객체·매핑·튜플 형태의 한 행을 컬럼명이 있는 dict 행으로 변환합니다.
def _row_dict(value: Any) -> dict[str, Any]:
    if isinstance(value, dict):
        return {str(key): _json_ready(item) for key, item in value.items()}
    return {"value": _json_ready(value)}


# 함수 설명: `_standard_result()`는 정상 조회 결과를 dataset/source alias와 rows가 포함된 공통 결과 구조로 만듭니다.
def _standard_result(job: dict[str, Any], rows: list[dict[str, Any]], params: dict[str, Any], method: str, url: str) -> dict[str, Any]:
    return {
        "source_alias": job.get("source_alias") or job.get("dataset_key"),
        "dataset_key": job.get("dataset_key"),
        "source_type": "h_api",
        "status": "ok",
        "row_count": len(rows),
        "columns": _rows_columns(rows),
        "preview_rows": rows[:PREVIEW_LIMIT],
        "rows": rows,
        "applied_params": deepcopy(params),
        "pandas_filters": deepcopy(job.get("filters", {})),
        "data_ref": "",
        "source_execution": {
            "used_dummy_data": False,
            "adapter": "h_api",
            "method": method,
            "api_url": url,
            "source_configured": True,
            "filters_applied_in_retriever": False,
        },
        "warnings": [],
        "errors": [],
    }


# 함수 설명: `_error_result()`는 예외 정보를 공통 errors 배열과 status가 포함된 실패 결과 구조로 만듭니다.
def _error_result(job: dict[str, Any], error_type: str, message: str, params: dict[str, Any] | None = None) -> dict[str, Any]:
    error = {"type": error_type, "message": message, "dataset_key": job.get("dataset_key", "")}
    return {
        "source_alias": job.get("source_alias") or job.get("dataset_key"),
        "dataset_key": job.get("dataset_key"),
        "source_type": "h_api",
        "status": "error",
        "row_count": 0,
        "columns": [],
        "preview_rows": [],
        "rows": [],
        "applied_params": deepcopy(params if params is not None else _job_params(job)),
        "pandas_filters": deepcopy(job.get("filters", {})),
        "data_ref": "",
        "source_execution": {"used_dummy_data": False, "adapter": "h_api", "source_configured": False},
        "warnings": [],
        "errors": [error],
    }


# 함수 설명: `_render_any()`는 ANY을 Markdown 또는 사용자 화면에서 안전하게 읽을 수 있는 표현으로 변환합니다.
def _render_any(value: Any, params: dict[str, Any], url_encode: bool) -> tuple[Any, list[str]]:
    if isinstance(value, str):
        return _render_template(value, params, url_encode=url_encode)
    if isinstance(value, dict):
        rendered = {}
        missing = []
        for key, item in value.items():
            next_value, next_missing = _render_any(item, params, url_encode=url_encode)
            rendered[str(key)] = next_value
            missing.extend(next_missing)
        return rendered, missing
    if isinstance(value, list):
        rendered_items = []
        missing = []
        for item in value:
            next_value, next_missing = _render_any(item, params, url_encode=url_encode)
            rendered_items.append(next_value)
            missing.extend(next_missing)
        return rendered_items, missing
    return value, []


# 함수 설명: `_render_template()`는 검증된 파라미터를 SQL·URL·본문 템플릿에 치환해 실제 요청 문자열을 만듭니다.
def _render_template(template: str, params: dict[str, Any], url_encode: bool) -> tuple[str, list[str]]:
    missing: list[str] = []

    # 함수 설명: `replace()`는 HTTP URL·본문 템플릿 placeholder를 요청 파라미터 값으로 치환하고 누락 key를 기록합니다.
    def replace(match: re.Match[str]) -> str:
        key = match.group(1).strip()
        value = _dict_get_ci(params, key)
        if value in (None, "", []):
            missing.append(key)
            return match.group(0)
        text = str(value)
        return urllib.parse.quote(text, safe="") if url_encode else text

    return re.sub(r"\{([^{}]+)\}", replace, str(template or "")), missing


# 함수 설명: `_missing_required_params()`는 필수 파라미터 중 실제 작업 값에 없는 항목을 찾아 오류 목록으로 반환합니다.
def _missing_required_params(params: dict[str, Any], required_params: Any) -> list[str]:
    missing = []
    for item in _as_list(required_params):
        key = str(item or "").strip()
        if key and _dict_get_ci(params, key) in (None, "", []):
            missing.append(key)
    return missing


# 함수 설명: `_rows_columns()`는 행 목록과 명시 컬럼을 함께 정규화해 표준 rows/columns 쌍을 만듭니다.
def _rows_columns(rows: list[dict[str, Any]]) -> list[str]:
    columns: list[str] = []
    for row in rows:
        for key in row:
            text = str(key)
            if text not in columns:
                columns.append(text)
    return columns


# 함수 설명: `_json_ready()`는 datetime·Decimal·NaN 등 JSON이 직접 표현하지 못하는 값을 안전한 기본형으로 재귀 변환합니다.
def _json_ready(value: Any) -> Any:
    if value is None or isinstance(value, (str, int, float, bool)):
        return value
    if isinstance(value, (datetime, date)):
        return value.isoformat()
    if isinstance(value, Decimal):
        return float(value)
    if isinstance(value, dict):
        return {str(key): _json_ready(item) for key, item in value.items()}
    if isinstance(value, (list, tuple, set)):
        return [_json_ready(item) for item in value]
    try:
        if value != value:
            return None
    except Exception:
        pass
    return str(value)


# 함수 설명: `_timeout()`는 HTTP timeout 입력을 허용 범위의 초 단위 숫자로 보정합니다.
def _timeout(value: Any) -> int:
    try:
        return max(1, int(value or 30))
    except Exception:
        return 30


# 함수 설명: `_fetch_limit()`는 설정된 조회 제한을 안전한 정수 범위로 보정합니다.
def _fetch_limit(value: Any) -> int:
    try:
        return max(1, int(value or 5000))
    except Exception:
        return 5000


# 함수 설명: `_source_type()`는 조회 작업의 source type을 표준 소문자 식별자로 정규화합니다.
def _source_type(value: Any) -> str:
    return str(value or "").strip().lower().replace("-", "_").replace(" ", "_")


# 함수 설명: `_normalize_key()`는 key의 대소문자·공백·구분자 차이를 제거해 비교 가능한 표준 식별자로 바꿉니다.
def _normalize_key(value: Any) -> str:
    return re.sub(r"[\s_-]+", "", str(value or "").strip().lower())


# 함수 설명: `_dict_get_ci()`는 키의 대소문자 차이를 무시하고 dict에서 요청한 값을 찾습니다.
def _dict_get_ci(mapping: dict[str, Any], key: Any, default: Any = None) -> Any:
    if not isinstance(mapping, dict):
        return default
    text = str(key or "").strip()
    if text in mapping:
        return mapping[text]
    normalized = _normalize_key(text)
    for item_key, value in mapping.items():
        if _normalize_key(item_key) == normalized:
            return value
    return default


# 함수 설명: `_as_list()`는 단일 값과 여러 값 입력을 모두 같은 list 형태로 맞춰 반복 처리를 단순화합니다.
def _as_list(value: Any) -> list[Any]:
    if value is None:
        return []
    if isinstance(value, list):
        return value
    if isinstance(value, tuple):
        return list(value)
    if isinstance(value, set):
        return list(value)
    return [value]


# 함수 설명: `_safe_decode()`는 bytes 응답을 UTF-8로 해석하고 실패해도 예외 대신 읽을 수 있는 문자열을 반환합니다.
def _safe_decode(value: Any) -> str:
    if isinstance(value, bytes):
        return value.decode("utf-8", errors="replace")
    return str(value or "")


# 함수 설명: `_payload()`는 Langflow Data/Message 또는 일반 dict 입력에서 안전한 dict 페이로드 복사본을 꺼냅니다.
def _payload(value: Any) -> dict[str, Any]:
    if isinstance(value, dict):
        return deepcopy(value)
    data = getattr(value, "data", None)
    return deepcopy(data) if isinstance(data, dict) else {}


# 함수 설명: `_skipped()`는 설정이나 대상 작업이 없어 실행하지 않은 이유를 표준 skipped 결과로 남깁니다.
def _skipped(source_type: str, reason: str) -> dict[str, Any]:
    return {"source_type": source_type, "status": "skipped", "skipped": True, "skip_reason": reason, "source_results": [], "errors": [], "warnings": []}


# Langflow 컴포넌트 클래스: inputs/outputs가 캔버스 포트와 JSON edge 계약을 정의합니다.
# 실제 업무 규칙은 위의 주요 함수에 두어 UI 실행과 단위 테스트가 같은 로직을 사용합니다.
class HApiRetriever(Component):
    display_name = "10 H-API 데이터 조회기"
    description = "table catalog의 H-API source_config를 사용해 실제 API 조회를 실행합니다."
    inputs = [
        DataInput(name="payload", display_name="페이로드", required=True),
        MessageTextInput(name="api_token", display_name="H-API 토큰", required=False, value="", advanced=True),
        MessageTextInput(name="timeout_seconds", display_name="요청 제한 시간(초)", required=False, value="30", advanced=True),
        MessageTextInput(name="fetch_limit", display_name="조회 제한 건수", required=False, value="5000", advanced=True),
    ]
    outputs = [Output(name="retrieval_payload", display_name="조회 페이로드", method="build_payload")]

    # Langflow 출력 함수: '조회 페이로드 (retrieval_payload)' 포트가 요청될 때 실행됩니다.
    # 핵심 처리 결과를 Langflow Data/Message 형식으로 감싸 다음 노드에 전달합니다.
    def build_payload(self) -> Data:
        return Data(
            data=h_api_retrieve(
                getattr(self, "payload", None),
                getattr(self, "api_token", ""),
                getattr(self, "timeout_seconds", ""),
                getattr(self, "fetch_limit", ""),
            )
        )

# -*- coding: utf-8 -*-
# =============================================================================
# 컴포넌트 개요: 11 데이터레이크 조회기
# 역할: table catalog의 Datalake source_config와 LakeHouse 계열 client를 사용해 실제 SQL 조회를 실행합니다.
# 주요 입력: 페이로드 (payload) · 필수, Datalake 모듈명 (module_name), Datalake 클래스명 (class_name), LakeHouse 사용자 ID (user_id),
#        LakeHouse 토큰 (token), S3 접근 키 (s3_access_key), S3 보안 키 (s3_secret_key), 조회 제한 건수 (fetch_limit)
# 주요 출력: 조회 페이로드 (retrieval_payload)
# 처리 흐름: 사내 Datalake 클라이언트를 동적으로 준비하고 SQL 결과의 다양한 반환 형식을 표준 rows로 변환합니다.
# 유지보수 포인트: 실행 오류를 다른 source의 성공처럼 위장하는 과도한 fallback은 만들지 말고 공통 errors 계약으로 전달합니다.
# =============================================================================

from __future__ import annotations

import os
import re
from copy import deepcopy
from datetime import date, datetime
from decimal import Decimal
from importlib import import_module
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, MessageTextInput, Output
from lfx.schema.data import Data


PREVIEW_LIMIT = 5


# 주요 함수: Datalake SQL 작업을 실행하고 결과 객체를 표준 행 목록으로 바꿉니다.
# Langflow 클래스와 단위 테스트가 같은 업무 규칙을 쓰도록 일반 Python 값 중심으로 처리합니다.
def datalake_retrieve(
    payload_value: Any,
    module_name: Any = "",
    class_name: Any = "",
    user_id: Any = "",
    token: Any = "",
    s3_access_key: Any = "",
    s3_secret_key: Any = "",
    fetch_limit: Any = "",
    client_cls: Any = None,
) -> dict[str, Any]:
    payload = _payload(payload_value)
    jobs = _jobs_for_source(payload)
    if not jobs:
        return _skipped("datalake", "no datalake retrieval jobs")

    limit = _fetch_limit(fetch_limit or os.getenv("SOURCE_FETCH_LIMIT", "5000"))
    client_factory = DatalakeClientFactory(
        module_name=str(module_name or os.getenv("DATALAKE_MODULE_NAME", "lakes")).strip(),
        class_name=str(class_name or os.getenv("DATALAKE_CLASS_NAME", "LakeHouse")).strip(),
        user_id=str(user_id or os.getenv("LAKEHOUSE_USER_ID", "")).strip(),
        token=str(token or os.getenv("LAKEHOUSE_TOKEN", "")).strip(),
        s3_access_key=str(s3_access_key or os.getenv("LAKEHOUSE_S3_ACCESS_KEY", "")).strip(),
        s3_secret_key=str(s3_secret_key or os.getenv("LAKEHOUSE_S3_SECRET_KEY", "")).strip(),
        client_cls=client_cls,
    )
    results = [_run_datalake_job(job, client_factory, limit) for job in jobs]
    errors = [error for result in results for error in result.get("errors", []) if isinstance(error, dict)]
    warnings = [warning for result in results for warning in result.get("warnings", []) if isinstance(warning, dict)]
    return {
        "source_type": "datalake",
        "status": "error" if errors else "ok",
        "skipped": False,
        "executed_jobs": [str(job.get("job_id") or job.get("dataset_key") or index) for index, job in enumerate(jobs, 1)],
        "source_results": results,
        "errors": errors,
        "warnings": warnings,
    }


# 함수 설명: `_run_datalake_job()`는 datalake·조회 작업 실행 경계를 담당하고 성공 결과와 오류를 공통 계약으로 반환합니다.
def _run_datalake_job(job: dict[str, Any], client_factory: "DatalakeClientFactory", fetch_limit: int) -> dict[str, Any]:
    source_config = _source_config(job)
    params = _job_params(job)
    missing = _missing_required_params(params, _required_param_names(job, source_config))
    if missing:
        return _error_result(job, "missing_required_params", f"필수 파라미터가 없습니다: {', '.join(missing)}", params=params)

    query_template = str(
        source_config.get("query_template")
        or source_config.get("sql_template")
        or source_config.get("datalake_sql")
        or source_config.get("sql")
        or source_config.get("query")
        or ""
    ).strip()
    if not query_template:
        return _error_result(job, "missing_query_template", "Datalake source_config에 query_template이 없습니다.", params=params)

    sql, missing_template_params = _render_template(query_template, params)
    if missing_template_params:
        return _error_result(job, "missing_template_params", f"SQL 템플릿 파라미터가 없습니다: {', '.join(missing_template_params)}", params=params)

    try:
        rows = client_factory.execute_sql(sql, source_config, fetch_limit)
        rows = _json_ready(rows)
        if not isinstance(rows, list):
            rows = []
        return _standard_result(job, rows, params, sql, client_factory.module_name, client_factory.class_name)
    except Exception as exc:
        return _error_result(job, "datalake_retrieval_failed", f"Datalake 조회 실패: {exc}", params=params)


# 내부 연동 도우미 클래스: 외부 라이브러리나 클라이언트 차이를 이 파일의 표준 호출 형태로 감쌉니다.
class DatalakeClientFactory:
    # 함수 설명: `__init__()`는 외부 클라이언트나 실행 설정을 인스턴스에 보관해 뒤의 메서드가 같은 연결 문맥을 사용하게 합니다.
    def __init__(
        self,
        module_name: str,
        class_name: str,
        user_id: str,
        token: str,
        s3_access_key: str,
        s3_secret_key: str,
        client_cls: Any = None,
    ):
        self.module_name = module_name or "lakes"
        self.class_name = class_name or "LakeHouse"
        self.user_id = user_id
        self.token = token
        self.s3_access_key = s3_access_key
        self.s3_secret_key = s3_secret_key
        self.client_cls = client_cls

    # 주요 메서드: Datalake 클라이언트에 SQL을 전달하고 원시 결과를 반환합니다.
    # Langflow의 동적 빌드 또는 공개 실행 계약에서 호출될 수 있으므로 이름과 반환형을 유지합니다.
    def execute_sql(self, sql: str, source_config: dict[str, Any], fetch_limit: int) -> list[dict[str, Any]]:
        self._prepare_environment()
        client = self._create_client()
        cluster_type = str(source_config.get("cluster_type") or os.getenv("LAKEHOUSE_CLUSTER_TYPE", "starrocks")).strip()
        if hasattr(client, "ensure_running"):
            self._call_with_fallback(client.ensure_running, {"cluster_type": cluster_type}, [cluster_type])
        raw_result = self._run_query_method(client, sql)
        rows = self._read_result(client, raw_result)
        return [_row_dict(row) for row in _rows_from_value(rows)[:fetch_limit]]

    # 함수 설명: `_prepare_environment()`는 명시적으로 제공된 Datalake 인증·접속 설정만 실행 환경변수에 반영합니다.
    def _prepare_environment(self) -> None:
        for key, value in {
            "LAKEHOUSE_USER_ID": self.user_id,
            "LAKEHOUSE_TOKEN": self.token,
            "LAKEHOUSE_S3_ACCESS_KEY": self.s3_access_key,
            "LAKEHOUSE_S3_SECRET_KEY": self.s3_secret_key,
        }.items():
            if value:
                os.environ[key] = value

    # 함수 설명: `_create_client()`는 client 구성 요소를 모아 다음 단계가 사용할 표준 결과로 만듭니다.
    def _create_client(self) -> Any:
        cls = self.client_cls or getattr(import_module(self.module_name), self.class_name)
        attempts = (
            ((), {"real_user_id": self.user_id}) if self.user_id else ((), {}),
            ((), {"user_id": self.user_id}) if self.user_id else ((), {}),
            ((), {}),
        )
        last_error = None
        for args, kwargs in attempts:
            try:
                return cls(*args, **kwargs)
            except TypeError as exc:
                last_error = exc
        if last_error:
            raise last_error
        return cls()

    # 함수 설명: `_run_query_method()`는 쿼리·method 실행 경계를 담당하고 성공 결과와 오류를 공통 계약으로 반환합니다.
    def _run_query_method(self, client: Any, sql: str) -> Any:
        if hasattr(client, "auto_run_sync_paragraph"):
            return self._call_with_fallback(client.auto_run_sync_paragraph, {"code": sql}, [sql])
        for method_name in ("run_sql", "execute_sql", "query", "execute", "read_sql"):
            if hasattr(client, method_name):
                return self._call_with_fallback(getattr(client, method_name), {"sql": sql}, [sql])
        raise AttributeError("Datalake client에 실행 메서드(auto_run_sync_paragraph/run_sql/query/execute)가 없습니다.")

    # 함수 설명: `_read_result()`는 입력 또는 외부 저장소에서 결과을 읽고 호출자가 사용할 형태로 반환합니다.
    def _read_result(self, client: Any, raw_result: Any) -> Any:
        if raw_result not in (None, ""):
            return raw_result
        if hasattr(client, "get_rst"):
            return client.get_rst()
        if hasattr(client, "get_result"):
            return client.get_result()
        return raw_result

    # 함수 설명: `_call_with_fallback()`는 WITH·fallback 실행 경계를 담당하고 성공 결과와 오류를 공통 계약으로 반환합니다.
    @staticmethod
    def _call_with_fallback(method: Any, kwargs: dict[str, Any], args: list[Any]) -> Any:
        try:
            return method(**kwargs)
        except TypeError:
            return method(*args)


# 함수 설명: `_jobs_for_source()`는 전체 조회 작업 중 지정한 source type에 해당하는 작업만 골라냅니다.
def _jobs_for_source(payload: dict[str, Any]) -> list[dict[str, Any]]:
    bundle = payload.get("retrieval_job_bundle") if isinstance(payload.get("retrieval_job_bundle"), dict) else {}
    bundle_jobs = bundle.get("jobs") if isinstance(bundle.get("jobs"), list) else []
    if bundle_jobs:
        return [deepcopy(job) for job in bundle_jobs if isinstance(job, dict)]
    plan = payload.get("intent_plan") if isinstance(payload.get("intent_plan"), dict) else {}
    jobs = plan.get("retrieval_jobs") if isinstance(plan.get("retrieval_jobs"), list) else []
    return [deepcopy(job) for job in jobs if isinstance(job, dict) and _source_type(job.get("source_type")) in {"datalake", "data_lake", "lakehouse"}]


# 함수 설명: `_source_config()`는 조회 작업 또는 카탈로그에서 허용된 데이터 소스 설정만 dict로 꺼냅니다.
def _source_config(job: dict[str, Any]) -> dict[str, Any]:
    config = deepcopy(job.get("source_config")) if isinstance(job.get("source_config"), dict) else {}
    for key in ("query_template", "sql_template", "datalake_sql", "sql", "query", "cluster_type"):
        if job.get(key) not in (None, "", [], {}):
            config.setdefault(key, deepcopy(job[key]))
    return config


# 함수 설명: `_job_params()`는 조회 작업의 params를 안전한 dict로 정리해 retriever에 전달합니다.
def _job_params(job: dict[str, Any]) -> dict[str, Any]:
    if isinstance(job.get("params"), dict):
        return deepcopy(job["params"])
    if isinstance(job.get("required_params"), dict):
        return deepcopy(job["required_params"])
    return {}


# 함수 설명: `_required_param_names()`는 카탈로그 설정에서 실행 전에 반드시 있어야 하는 파라미터 이름을 추출합니다.
def _required_param_names(job: dict[str, Any], source_config: dict[str, Any]) -> list[Any]:
    if isinstance(source_config.get("required_params"), (list, tuple, set)):
        return _as_list(source_config.get("required_params"))
    if isinstance(job.get("required_param_names"), (list, tuple, set)):
        return _as_list(job.get("required_param_names"))
    if not isinstance(job.get("required_params"), dict):
        return _as_list(job.get("required_params"))
    return []


# 함수 설명: `_standard_result()`는 정상 조회 결과를 dataset/source alias와 rows가 포함된 공통 결과 구조로 만듭니다.
def _standard_result(
    job: dict[str, Any],
    rows: list[dict[str, Any]],
    params: dict[str, Any],
    sql: str,
    module_name: str,
    class_name: str,
) -> dict[str, Any]:
    return {
        "source_alias": job.get("source_alias") or job.get("dataset_key"),
        "dataset_key": job.get("dataset_key"),
        "source_type": "datalake",
        "status": "ok",
        "row_count": len(rows),
        "columns": _rows_columns(rows),
        "preview_rows": rows[:PREVIEW_LIMIT],
        "rows": rows,
        "applied_params": deepcopy(params),
        "pandas_filters": deepcopy(job.get("filters", {})),
        "data_ref": "",
        "source_execution": {
            "used_dummy_data": False,
            "adapter": "datalake",
            "module_name": module_name,
            "class_name": class_name,
            "executed_query": sql,
            "source_configured": True,
            "filters_applied_in_retriever": False,
        },
        "warnings": [],
        "errors": [],
    }


# 함수 설명: `_error_result()`는 예외 정보를 공통 errors 배열과 status가 포함된 실패 결과 구조로 만듭니다.
def _error_result(job: dict[str, Any], error_type: str, message: str, params: dict[str, Any] | None = None) -> dict[str, Any]:
    error = {"type": error_type, "message": message, "dataset_key": job.get("dataset_key", "")}
    return {
        "source_alias": job.get("source_alias") or job.get("dataset_key"),
        "dataset_key": job.get("dataset_key"),
        "source_type": "datalake",
        "status": "error",
        "row_count": 0,
        "columns": [],
        "preview_rows": [],
        "rows": [],
        "applied_params": deepcopy(params if params is not None else _job_params(job)),
        "pandas_filters": deepcopy(job.get("filters", {})),
        "data_ref": "",
        "source_execution": {"used_dummy_data": False, "adapter": "datalake", "source_configured": False},
        "warnings": [],
        "errors": [error],
    }


# 함수 설명: `_render_template()`는 검증된 파라미터를 SQL·URL·본문 템플릿에 치환해 실제 요청 문자열을 만듭니다.
def _render_template(template: str, params: dict[str, Any]) -> tuple[str, list[str]]:
    missing: list[str] = []

    # 함수 설명: `replace()`는 Datalake SQL 템플릿 placeholder를 자료형에 맞는 SQL literal로 치환하고 누락 key를 기록합니다.
    def replace(match: re.Match[str]) -> str:
        key = match.group(1).strip()
        value = _dict_get_ci(params, key)
        if value in (None, "", []):
            missing.append(key)
            return match.group(0)
        return _sql_literal(value)

    return re.sub(r"\{([^{}]+)\}", replace, str(template or "")), missing


# 함수 설명: `_sql_literal()`는 SQL 템플릿 파라미터를 자료형에 맞는 안전한 literal 표현으로 변환합니다.
def _sql_literal(value: Any) -> str:
    if value is None:
        return "NULL"
    if isinstance(value, (list, tuple, set)):
        return ", ".join(_sql_literal(item) for item in value)
    if isinstance(value, (datetime, date)):
        return f"'{value.strftime('%Y%m%d')}'"
    if isinstance(value, Decimal):
        return str(value)
    if isinstance(value, (int, float)) and not isinstance(value, bool):
        return str(value)
    return "'" + str(value).replace("'", "''") + "'"


# 함수 설명: `_missing_required_params()`는 필수 파라미터 중 실제 작업 값에 없는 항목을 찾아 오류 목록으로 반환합니다.
def _missing_required_params(params: dict[str, Any], required_params: Any) -> list[str]:
    missing = []
    for item in _as_list(required_params):
        key = str(item or "").strip()
        if key and _dict_get_ci(params, key) in (None, "", []):
            missing.append(key)
    return missing


# 함수 설명: `_rows_from_value()`는 외부 클라이언트의 DataFrame·list·dict 결과를 공통 dict 행 목록으로 변환합니다.
def _rows_from_value(value: Any) -> list[Any]:
    if isinstance(value, list):
        return value
    if isinstance(value, dict):
        for key in ("rows", "data", "items", "result", "results", "records"):
            if isinstance(value.get(key), list):
                return value[key]
            if isinstance(value.get(key), dict):
                nested = _rows_from_value(value[key])
                if nested:
                    return nested
        return [value]
    if value in (None, ""):
        return []
    if hasattr(value, "to_dict"):
        try:
            return value.to_dict(orient="records")
        except TypeError:
            return value.to_dict()
    return [{"value": value}]


# 함수 설명: `_row_dict()`는 객체·매핑·튜플 형태의 한 행을 컬럼명이 있는 dict 행으로 변환합니다.
def _row_dict(value: Any) -> dict[str, Any]:
    if isinstance(value, dict):
        return {str(key): _json_ready(item) for key, item in value.items()}
    return {"value": _json_ready(value)}


# 함수 설명: `_rows_columns()`는 행 목록과 명시 컬럼을 함께 정규화해 표준 rows/columns 쌍을 만듭니다.
def _rows_columns(rows: list[dict[str, Any]]) -> list[str]:
    columns: list[str] = []
    for row in rows:
        for key in row:
            text = str(key)
            if text not in columns:
                columns.append(text)
    return columns


# 함수 설명: `_json_ready()`는 datetime·Decimal·NaN 등 JSON이 직접 표현하지 못하는 값을 안전한 기본형으로 재귀 변환합니다.
def _json_ready(value: Any) -> Any:
    if value is None or isinstance(value, (str, int, float, bool)):
        return value
    if isinstance(value, (datetime, date)):
        return value.isoformat()
    if isinstance(value, Decimal):
        return float(value)
    if isinstance(value, dict):
        return {str(key): _json_ready(item) for key, item in value.items()}
    if isinstance(value, (list, tuple, set)):
        return [_json_ready(item) for item in value]
    try:
        if value != value:
            return None
    except Exception:
        pass
    return str(value)


# 함수 설명: `_fetch_limit()`는 설정된 조회 제한을 안전한 정수 범위로 보정합니다.
def _fetch_limit(value: Any) -> int:
    try:
        return max(1, int(value or 5000))
    except Exception:
        return 5000


# 함수 설명: `_source_type()`는 조회 작업의 source type을 표준 소문자 식별자로 정규화합니다.
def _source_type(value: Any) -> str:
    return str(value or "").strip().lower().replace("-", "_").replace(" ", "_")


# 함수 설명: `_normalize_key()`는 key의 대소문자·공백·구분자 차이를 제거해 비교 가능한 표준 식별자로 바꿉니다.
def _normalize_key(value: Any) -> str:
    return re.sub(r"[\s_-]+", "", str(value or "").strip().lower())


# 함수 설명: `_dict_get_ci()`는 키의 대소문자 차이를 무시하고 dict에서 요청한 값을 찾습니다.
def _dict_get_ci(mapping: dict[str, Any], key: Any, default: Any = None) -> Any:
    if not isinstance(mapping, dict):
        return default
    text = str(key or "").strip()
    if text in mapping:
        return mapping[text]
    normalized = _normalize_key(text)
    for item_key, value in mapping.items():
        if _normalize_key(item_key) == normalized:
            return value
    return default


# 함수 설명: `_as_list()`는 단일 값과 여러 값 입력을 모두 같은 list 형태로 맞춰 반복 처리를 단순화합니다.
def _as_list(value: Any) -> list[Any]:
    if value is None:
        return []
    if isinstance(value, list):
        return value
    if isinstance(value, tuple):
        return list(value)
    if isinstance(value, set):
        return list(value)
    return [value]


# 함수 설명: `_payload()`는 Langflow Data/Message 또는 일반 dict 입력에서 안전한 dict 페이로드 복사본을 꺼냅니다.
def _payload(value: Any) -> dict[str, Any]:
    if isinstance(value, dict):
        return deepcopy(value)
    data = getattr(value, "data", None)
    return deepcopy(data) if isinstance(data, dict) else {}


# 함수 설명: `_skipped()`는 설정이나 대상 작업이 없어 실행하지 않은 이유를 표준 skipped 결과로 남깁니다.
def _skipped(source_type: str, reason: str) -> dict[str, Any]:
    return {"source_type": source_type, "status": "skipped", "skipped": True, "skip_reason": reason, "source_results": [], "errors": [], "warnings": []}


# Langflow 컴포넌트 클래스: inputs/outputs가 캔버스 포트와 JSON edge 계약을 정의합니다.
# 실제 업무 규칙은 위의 주요 함수에 두어 UI 실행과 단위 테스트가 같은 로직을 사용합니다.
class DatalakeRetriever(Component):
    display_name = "11 데이터레이크 조회기"
    description = "table catalog의 Datalake source_config와 LakeHouse 계열 client를 사용해 실제 SQL 조회를 실행합니다."
    inputs = [
        DataInput(name="payload", display_name="페이로드", required=True),
        MessageTextInput(name="module_name", display_name="Datalake 모듈명", required=False, value="lakes", advanced=True),
        MessageTextInput(name="class_name", display_name="Datalake 클래스명", required=False, value="LakeHouse", advanced=True),
        MessageTextInput(name="user_id", display_name="LakeHouse 사용자 ID", required=False, value="", advanced=True),
        MessageTextInput(name="token", display_name="LakeHouse 토큰", required=False, value="", advanced=True),
        MessageTextInput(name="s3_access_key", display_name="S3 접근 키", required=False, value="", advanced=True),
        MessageTextInput(name="s3_secret_key", display_name="S3 보안 키", required=False, value="", advanced=True),
        MessageTextInput(name="fetch_limit", display_name="조회 제한 건수", required=False, value="5000", advanced=True),
    ]
    outputs = [Output(name="retrieval_payload", display_name="조회 페이로드", method="build_payload")]

    # Langflow 출력 함수: '조회 페이로드 (retrieval_payload)' 포트가 요청될 때 실행됩니다.
    # 핵심 처리 결과를 Langflow Data/Message 형식으로 감싸 다음 노드에 전달합니다.
    def build_payload(self) -> Data:
        return Data(
            data=datalake_retrieve(
                getattr(self, "payload", None),
                getattr(self, "module_name", ""),
                getattr(self, "class_name", ""),
                getattr(self, "user_id", ""),
                getattr(self, "token", ""),
                getattr(self, "s3_access_key", ""),
                getattr(self, "s3_secret_key", ""),
                getattr(self, "fetch_limit", ""),
            )
        )

# -*- coding: utf-8 -*-
# =============================================================================
# 컴포넌트 개요: 12 Goodocs 조회기
# 역할: Goodocs 문서 기반 source job을 실행하고, dummy 모드에서만 인증이 없을 때 fixture fallback을 허용합니다.
# 주요 입력: 페이로드 (payload) · 필수, Goodocs 사용자 ID (user_id), Goodocs 토큰 소스 (token_source), Goodocs 토큰 키 (token_key), 조회
#        제한 건수 (fetch_limit)
# 주요 출력: 조회 페이로드 (retrieval_payload)
# 처리 흐름: Goodocs 문서 또는 inline rows를 읽고 시스템 컬럼을 정리해 공통 source result 형식으로 반환합니다.
# 유지보수 포인트: 실행 오류를 다른 source의 성공처럼 위장하는 과도한 fallback은 만들지 말고 공통 errors 계약으로 전달합니다.
# =============================================================================

from __future__ import annotations

import json
import os
from copy import deepcopy
from datetime import date, datetime
from decimal import Decimal
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, MessageTextInput, Output
from lfx.schema.data import Data


GOODOCS_SYSTEM_COLUMNS = {"ROW_INDEX", "LastUser", "LastTime", "LastEditType", "FirstUser", "FirstTime", "ROW_ID"}
PREVIEW_LIMIT = 5


# 내부 연동 도우미 클래스: 외부 라이브러리나 클라이언트 차이를 이 파일의 표준 호출 형태로 감쌉니다.
class Goodocs:
    # 함수 설명: `__init__()`는 외부 클라이언트나 실행 설정을 인스턴스에 보관해 뒤의 메서드가 같은 연결 문맥을 사용하게 합니다.
    def __init__(self, auth: dict[str, Any]):
        self.auth = auth

    # 주요 메서드: Goodocs 클라이언트에서 문서의 전체 행을 읽습니다.
    # Langflow의 동적 빌드 또는 공개 실행 계약에서 호출될 수 있으므로 이름과 반환형을 유지합니다.
    def read_all(self) -> Any:
        raise RuntimeError("Goodocs class implementation is not configured. Paste the real Goodocs class into this component.")


# 주요 함수: Goodocs 또는 inline 데이터를 읽어 분석용 표준 행 목록으로 바꿉니다.
# Langflow 클래스와 단위 테스트가 같은 업무 규칙을 쓰도록 일반 Python 값 중심으로 처리합니다.
def goodocs_retrieve(
    payload_value: Any,
    user_id: Any = "",
    token_source: Any = "",
    token_key: Any = "",
    fetch_limit: Any = "",
) -> dict[str, Any]:
    payload = _payload(payload_value)
    jobs = _jobs_for_source(payload)
    if not jobs:
        return _skipped("goodocs", "no goodocs retrieval jobs")

    limit = _fetch_limit(fetch_limit or os.getenv("SOURCE_FETCH_LIMIT", "5000"))
    resolved_user_id = str(user_id or os.getenv("GOODOCS_USER_ID", "")).strip()
    resolved_token_source = str(token_source or os.getenv("GOODOCS_TOKEN_SOURCE", "")).strip()
    resolved_token_key = str(token_key or os.getenv("GOODOCS_TOKEN_KEY") or os.getenv("GOODOCS_TOKEN", "")).strip()
    retrieval_mode = _retrieval_mode(payload)
    results = [
        _run_goodocs_job(job, resolved_user_id, resolved_token_source, resolved_token_key, limit, retrieval_mode)
        for job in jobs
    ]
    errors = [error for result in results for error in result.get("errors", []) if isinstance(error, dict)]
    warnings = [warning for result in results for warning in result.get("warnings", []) if isinstance(warning, dict)]
    return {
        "source_type": "goodocs",
        "status": "error" if errors else "ok",
        "skipped": False,
        "executed_jobs": [str(job.get("job_id") or job.get("dataset_key") or index) for index, job in enumerate(jobs, 1)],
        "source_results": results,
        "errors": errors,
        "warnings": warnings,
    }


retrieve_goodocs_data = goodocs_retrieve


# 함수 설명: `_run_goodocs_job()`는 goodocs·조회 작업 실행 경계를 담당하고 성공 결과와 오류를 공통 계약으로 반환합니다.
def _run_goodocs_job(
    job: dict[str, Any],
    user_id: str,
    token_source: str,
    token_key: str,
    fetch_limit: int,
    retrieval_mode: str,
) -> dict[str, Any]:
    source_config = _source_config(job)
    params = _job_params(job)
    missing = _missing_required_params(params, _required_param_names(job, source_config))
    if missing:
        return _error_result(job, "missing_required_params", f"필수 파라미터가 없습니다: {', '.join(missing)}", params=params)

    doc_id = str(source_config.get("doc_id") or "").strip()
    sheet_name = str(source_config.get("sheet_name") or source_config.get("sheet") or "").strip()
    if not doc_id and not _has_inline_rows(source_config):
        return _error_result(job, "missing_doc_id", "Goodocs source_config에 doc_id가 없습니다.", params=params)

    inline_rows = _inline_rows(source_config)
    if inline_rows:
        rows = _drop_system_columns([_row_dict(row) for row in inline_rows])[:fetch_limit]
        return _standard_result(job, rows, params, source_config, used_dummy_data=False, source_configured=True)

    credentials = {"USER_ID": user_id, "TOKEN_SOURCE": token_source, "TOKEN_KEY": token_key}
    if not any(str(value or "").strip() for value in credentials.values()):
        if retrieval_mode == "live":
            return _error_result(
                job,
                "missing_goodocs_credentials",
                "live 모드에서는 Goodocs 인증 누락 시 dummy fallback을 사용하지 않습니다.",
                params=params,
            )
        rows = _dummy_rows(job, doc_id)[:fetch_limit]
        return _standard_result(job, rows, params, source_config, used_dummy_data=True, source_configured=False)

    missing_credentials = [key for key, value in credentials.items() if not str(value or "").strip()]
    if missing_credentials:
        return _error_result(
            job,
            "missing_goodocs_credentials",
            f"Goodocs 인증 값이 없습니다: {', '.join(missing_credentials)}",
            params=params,
        )

    auth = {"USER_ID": user_id, "DOC_ID": doc_id, "TOKEN_SOURCE": token_source, "TOKEN_KEY": token_key}
    if sheet_name:
        auth["SHEET_NAME"] = sheet_name
    try:
        goodocs_cls = _goodocs_class()
        goodocs = goodocs_cls(auth)
        if sheet_name and hasattr(goodocs, "read_sheet"):
            frame = goodocs.read_sheet(sheet_name)
        else:
            frame = goodocs.read_all()
        rows = _frame_to_rows(frame)[:fetch_limit]
        return _standard_result(job, rows, params, source_config, used_dummy_data=False, source_configured=True)
    except Exception as exc:
        return _error_result(job, "goodocs_retrieval_failed", f"Goodocs 조회 실패: {exc}", params=params)


# 함수 설명: `_goodocs_class()`는 테스트 override가 있으면 우선 사용하고 아니면 기본 Goodocs 클라이언트 class를 가져옵니다.
def _goodocs_class() -> Any:
    override = getattr(GoodocsRetriever, "goodocs_class", None) if "GoodocsRetriever" in globals() else None
    if override is not None:
        return override
    return Goodocs


# 함수 설명: `_jobs_for_source()`는 전체 조회 작업 중 지정한 source type에 해당하는 작업만 골라냅니다.
def _jobs_for_source(payload: dict[str, Any]) -> list[dict[str, Any]]:
    bundle = payload.get("retrieval_job_bundle") if isinstance(payload.get("retrieval_job_bundle"), dict) else {}
    bundle_jobs = bundle.get("jobs") if isinstance(bundle.get("jobs"), list) else []
    if bundle_jobs:
        return [
            deepcopy(job)
            for job in bundle_jobs
            if isinstance(job, dict)
            and _source_type(job.get("source_type") or _source_config(job).get("source_type")) in {"goodocs", "goodoc", "godocs"}
        ]
    plan = payload.get("intent_plan") if isinstance(payload.get("intent_plan"), dict) else payload
    jobs = plan.get("retrieval_jobs") if isinstance(plan.get("retrieval_jobs"), list) else []
    return [
        deepcopy(job)
        for job in jobs
        if isinstance(job, dict) and _source_type(job.get("source_type") or _source_config(job).get("source_type")) in {"goodocs", "goodoc", "godocs"}
    ]


# 함수 설명: `_source_config()`는 조회 작업 또는 카탈로그에서 허용된 데이터 소스 설정만 dict로 꺼냅니다.
def _source_config(job: dict[str, Any]) -> dict[str, Any]:
    config = deepcopy(job.get("source_config")) if isinstance(job.get("source_config"), dict) else {}
    for key in ("doc_id", "document_id", "sheet_name", "sheet", "range", "table_name", "columns", "required_columns", "rows", "data", "items"):
        if job.get(key) not in (None, "", [], {}):
            config.setdefault(key, deepcopy(job[key]))
    if config.get("document_id") and not config.get("doc_id"):
        config["doc_id"] = config["document_id"]
    return config


# 함수 설명: `_job_params()`는 조회 작업의 params를 안전한 dict로 정리해 retriever에 전달합니다.
def _job_params(job: dict[str, Any]) -> dict[str, Any]:
    if isinstance(job.get("params"), dict):
        return deepcopy(job["params"])
    if isinstance(job.get("required_params"), dict):
        return deepcopy(job["required_params"])
    return {}


# 함수 설명: `_required_param_names()`는 카탈로그 설정에서 실행 전에 반드시 있어야 하는 파라미터 이름을 추출합니다.
def _required_param_names(job: dict[str, Any], source_config: dict[str, Any]) -> list[Any]:
    if isinstance(source_config.get("required_params"), (list, tuple, set)):
        return _as_list(source_config.get("required_params"))
    if isinstance(job.get("required_param_names"), (list, tuple, set)):
        return _as_list(job.get("required_param_names"))
    if not isinstance(job.get("required_params"), dict):
        return _as_list(job.get("required_params"))
    return []


# 함수 설명: `_standard_result()`는 정상 조회 결과를 dataset/source alias와 rows가 포함된 공통 결과 구조로 만듭니다.
def _standard_result(
    job: dict[str, Any],
    rows: list[dict[str, Any]],
    params: dict[str, Any],
    source_config: dict[str, Any],
    used_dummy_data: bool,
    source_configured: bool,
) -> dict[str, Any]:
    return {
        "success": True,
        "source_alias": job.get("source_alias") or job.get("dataset_key"),
        "dataset_key": job.get("dataset_key"),
        "source_type": "goodocs",
        "status": "ok",
        "row_count": len(rows),
        "columns": _rows_columns(rows),
        "preview_rows": rows[:PREVIEW_LIMIT],
        "rows": rows,
        "applied_params": deepcopy(params),
        "applied_filters": deepcopy(job.get("filters", [])),
        "pandas_filters": deepcopy(job.get("filters", {})),
        "data_ref": "",
        "summary": f"{job.get('dataset_key', 'source')} goodocs retrieval complete: {len(rows)} rows",
        "source_execution": {
            "used_dummy_data": used_dummy_data,
            "adapter": "goodocs",
            "doc_id": source_config.get("doc_id") or "",
            "sheet_name": source_config.get("sheet_name") or source_config.get("sheet") or "",
            "range": source_config.get("range") or "",
            "source_configured": source_configured,
            "filters_applied_in_retriever": False,
        },
        "warnings": [],
        "errors": [],
    }


# 함수 설명: `_error_result()`는 예외 정보를 공통 errors 배열과 status가 포함된 실패 결과 구조로 만듭니다.
def _error_result(job: dict[str, Any], error_type: str, message: str, params: dict[str, Any] | None = None) -> dict[str, Any]:
    error = {"type": error_type, "message": message, "dataset_key": job.get("dataset_key", "")}
    return {
        "success": False,
        "source_alias": job.get("source_alias") or job.get("dataset_key"),
        "dataset_key": job.get("dataset_key"),
        "source_type": "goodocs",
        "status": "error",
        "row_count": 0,
        "columns": [],
        "preview_rows": [],
        "rows": [],
        "applied_params": deepcopy(params if params is not None else _job_params(job)),
        "applied_filters": deepcopy(job.get("filters", [])),
        "pandas_filters": deepcopy(job.get("filters", {})),
        "data_ref": "",
        "summary": "",
        "failure_type": error_type,
        "error_message": message,
        "source_execution": {"used_dummy_data": False, "adapter": "goodocs", "source_configured": False},
        "warnings": [],
        "errors": [error],
    }


# 함수 설명: `_dummy_rows()`는 행 목록을 표준 행 목록으로 생성하거나 입력 행 중 필요한 부분만 선택합니다.
def _dummy_rows(job: dict[str, Any], doc_id: str) -> list[dict[str, Any]]:
    params = _job_params(job)
    rows = []
    for index in range(20):
        rows.append(
            {
                "DATE": params.get("DATE", "2026-06-12"),
                "TECH": "TSV" if index % 4 == 0 else "FC",
                "DEN": "2048G" if index % 4 == 0 else "128G",
                "MODE": "HBM3E" if index % 4 == 0 else "LPDDR5",
                "PKG_TYPE1": "HBM" if index % 4 == 0 else "UFBGA",
                "PKG_TYPE2": "HBM" if index % 4 == 0 else "MOBILE",
                "LEAD": "LF",
                "MCP_NO": "H-HBM16E" if index % 4 == 0 else "EMPTY",
                "INPUT_PLAN": 120000 + index * 2000,
                "OUT_PLAN": 90000 + index * 1500,
                "doc_id": doc_id,
            }
        )
    return rows


# 함수 설명: `_frame_to_rows()`는 TO·행 목록을 표준 행 목록으로 생성하거나 입력 행 중 필요한 부분만 선택합니다.
def _frame_to_rows(frame: Any) -> list[dict[str, Any]]:
    if hasattr(frame, "reset_index"):
        try:
            frame = frame.reset_index(drop=True)
        except Exception:
            pass
    if hasattr(frame, "drop"):
        try:
            drop_columns = [column for column in GOODOCS_SYSTEM_COLUMNS if column in getattr(frame, "columns", [])]
            if drop_columns:
                frame = frame.drop(columns=drop_columns)
        except Exception:
            pass
    return _drop_system_columns([_row_dict(row) for row in _rows_from_value(frame)])


# 함수 설명: `_inline_rows()`는 행 목록을 표준 행 목록으로 생성하거나 입력 행 중 필요한 부분만 선택합니다.
def _inline_rows(source_config: dict[str, Any]) -> list[Any]:
    for key in ("rows", "data", "items"):
        if isinstance(source_config.get(key), list):
            return deepcopy(source_config[key])
    return []


# 함수 설명: `_has_inline_rows()`는 입력값이 inline·행 목록 조건에 해당하는지 부작용 없이 bool로 판정합니다.
def _has_inline_rows(source_config: dict[str, Any]) -> bool:
    return bool(_inline_rows(source_config))


# 함수 설명: `_rows_from_value()`는 외부 클라이언트의 DataFrame·list·dict 결과를 공통 dict 행 목록으로 변환합니다.
def _rows_from_value(value: Any) -> list[Any]:
    if isinstance(value, list):
        return value
    if isinstance(value, dict):
        for key in ("rows", "data", "items", "result", "results", "records"):
            if isinstance(value.get(key), list):
                return value[key]
            if isinstance(value.get(key), dict):
                nested = _rows_from_value(value[key])
                if nested:
                    return nested
        return [value]
    if value is None or (isinstance(value, str) and value == ""):
        return []
    if hasattr(value, "to_dict"):
        try:
            return value.to_dict(orient="records")
        except TypeError:
            return value.to_dict("records")
    return [{"value": value}]


# 함수 설명: `_drop_system_columns()`는 system·컬럼에서 후속 단계에 불필요하거나 노출하면 안 되는 부분을 제거합니다.
def _drop_system_columns(rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    return [{key: value for key, value in row.items() if str(key) not in GOODOCS_SYSTEM_COLUMNS} for row in rows]


# 함수 설명: `_row_dict()`는 객체·매핑·튜플 형태의 한 행을 컬럼명이 있는 dict 행으로 변환합니다.
def _row_dict(value: Any) -> dict[str, Any]:
    if isinstance(value, dict):
        return {str(key): _json_ready(item) for key, item in value.items()}
    return {"value": _json_ready(value)}


# 함수 설명: `_rows_columns()`는 행 목록과 명시 컬럼을 함께 정규화해 표준 rows/columns 쌍을 만듭니다.
def _rows_columns(rows: list[dict[str, Any]]) -> list[str]:
    columns: list[str] = []
    for row in rows:
        for key in row:
            text = str(key)
            if text not in columns:
                columns.append(text)
    return columns


# 함수 설명: `_json_ready()`는 datetime·Decimal·NaN 등 JSON이 직접 표현하지 못하는 값을 안전한 기본형으로 재귀 변환합니다.
def _json_ready(value: Any) -> Any:
    if value is None or isinstance(value, (str, int, float, bool)):
        return value
    if isinstance(value, (datetime, date)):
        return value.isoformat()
    if isinstance(value, Decimal):
        return float(value)
    if isinstance(value, dict):
        return {str(key): _json_ready(item) for key, item in value.items()}
    if isinstance(value, (list, tuple, set)):
        return [_json_ready(item) for item in value]
    try:
        if value != value:
            return None
    except Exception:
        pass
    return str(value)


# 함수 설명: `_missing_required_params()`는 필수 파라미터 중 실제 작업 값에 없는 항목을 찾아 오류 목록으로 반환합니다.
def _missing_required_params(params: dict[str, Any], required_params: Any) -> list[str]:
    missing = []
    for item in _as_list(required_params):
        key = str(item or "").strip()
        if key and _dict_get_ci(params, key) in (None, "", []):
            missing.append(key)
    return missing


# 함수 설명: `_fetch_limit()`는 설정된 조회 제한을 안전한 정수 범위로 보정합니다.
def _fetch_limit(value: Any) -> int:
    try:
        return max(1, int(value or 5000))
    except Exception:
        return 5000


# 함수 설명: `_source_type()`는 조회 작업의 source type을 표준 소문자 식별자로 정규화합니다.
def _source_type(value: Any) -> str:
    return str(value or "").strip().lower().replace("-", "_").replace(" ", "_")


# 함수 설명: `_retrieval_mode()`는 request와 routed bundle에서 현재 dummy/live 실행 모드를 확인합니다.
def _retrieval_mode(payload: dict[str, Any]) -> str:
    request = payload.get("request") if isinstance(payload.get("request"), dict) else {}
    bundle = payload.get("retrieval_job_bundle") if isinstance(payload.get("retrieval_job_bundle"), dict) else {}
    mode = str(request.get("retrieval_mode") or bundle.get("retrieval_mode") or "dummy").strip().lower()
    return "live" if mode in {"live", "actual", "real", "실제", "true", "on", "1", "yes"} else "dummy"


# 함수 설명: `_normalize_key()`는 key의 대소문자·공백·구분자 차이를 제거해 비교 가능한 표준 식별자로 바꿉니다.
def _normalize_key(value: Any) -> str:
    return str(value or "").strip().lower().replace("_", "").replace("-", "").replace(" ", "")


# 함수 설명: `_dict_get_ci()`는 키의 대소문자 차이를 무시하고 dict에서 요청한 값을 찾습니다.
def _dict_get_ci(mapping: dict[str, Any], key: Any, default: Any = None) -> Any:
    if not isinstance(mapping, dict):
        return default
    text = str(key or "").strip()
    if text in mapping:
        return mapping[text]
    normalized = _normalize_key(text)
    for item_key, value in mapping.items():
        if _normalize_key(item_key) == normalized:
            return value
    return default


# 함수 설명: `_as_list()`는 단일 값과 여러 값 입력을 모두 같은 list 형태로 맞춰 반복 처리를 단순화합니다.
def _as_list(value: Any) -> list[Any]:
    if value is None:
        return []
    if isinstance(value, list):
        return value
    if isinstance(value, tuple):
        return list(value)
    if isinstance(value, set):
        return list(value)
    return [value]


# 함수 설명: `_payload()`는 Langflow Data/Message 또는 일반 dict 입력에서 안전한 dict 페이로드 복사본을 꺼냅니다.
def _payload(value: Any) -> dict[str, Any]:
    if isinstance(value, dict):
        return deepcopy(value)
    data = getattr(value, "data", None)
    if isinstance(data, dict):
        return deepcopy(data)
    text = getattr(value, "text", None) or getattr(value, "content", None)
    if isinstance(text, str):
        try:
            parsed = json.loads(text)
            return parsed if isinstance(parsed, dict) else {"text": text}
        except Exception:
            return {"text": text}
    return {}


# 함수 설명: `_skipped()`는 설정이나 대상 작업이 없어 실행하지 않은 이유를 표준 skipped 결과로 남깁니다.
def _skipped(source_type: str, reason: str) -> dict[str, Any]:
    return {"source_type": source_type, "status": "skipped", "skipped": True, "skip_reason": reason, "source_results": [], "errors": [], "warnings": []}


# Langflow 컴포넌트 클래스: inputs/outputs가 캔버스 포트와 JSON edge 계약을 정의합니다.
# 실제 업무 규칙은 위의 주요 함수에 두어 UI 실행과 단위 테스트가 같은 로직을 사용합니다.
class GoodocsRetriever(Component):
    goodocs_class = None

    display_name = "12 Goodocs 조회기"
    description = "Goodocs 문서 기반 source job을 실행하며, live 모드에서는 인증 누락을 오류로 반환합니다."
    inputs = [
        DataInput(name="payload", display_name="페이로드", required=True),
        MessageTextInput(name="user_id", display_name="Goodocs 사용자 ID", required=False, value="", advanced=True),
        MessageTextInput(name="token_source", display_name="Goodocs 토큰 소스", required=False, value="", advanced=True),
        MessageTextInput(name="token_key", display_name="Goodocs 토큰 키", required=False, value="", advanced=True),
        MessageTextInput(name="fetch_limit", display_name="조회 제한 건수", required=False, value="5000", advanced=True),
    ]
    outputs = [Output(name="retrieval_payload", display_name="조회 페이로드", method="build_payload")]

    # Langflow 출력 함수: '조회 페이로드 (retrieval_payload)' 포트가 요청될 때 실행됩니다.
    # 핵심 처리 결과를 Langflow Data/Message 형식으로 감싸 다음 노드에 전달합니다.
    def build_payload(self) -> Data:
        return Data(
            data=goodocs_retrieve(
                getattr(self, "payload", None),
                getattr(self, "user_id", ""),
                getattr(self, "token_source", ""),
                getattr(self, "token_key", ""),
                getattr(self, "fetch_limit", ""),
            )
        )
